Arduino/HERO Code (.ino):
/*
  Blink

  Turns an LED on for one second, then off for one second, repeatedly.

  Most Arduinos have an on-board LED you can control. On the UNO, MEGA and ZERO
  it is attached to digital pin 13, on MKR1000 on pin 6. LED_BUILTIN is set to
  the correct LED pin independent of which board is used.
  If you want to know what pin the on-board LED is connected to on your Arduino
  model, check the Technical Specs of your board at:
  https://www.arduino.cc/en/Main/Products

  modified 8 May 2014
  by Scott Fitzgerald
  modified 2 Sep 2016
  by Arturo Guadalupi
  modified 8 Sep 2016
  by Colby Newman

  This example code is in the public domain.

  https://www.arduino.cc/en/Tutorial/BuiltInExamples/Blink
*/

// the setup function runs once when you press reset or power the board
void setup() {
  // initialize digital pin LED_BUILTIN as an output.
  pinMode(LED_BUILTIN, OUTPUT);
}

// the loop function runs over and over again forever
void loop() {
  digitalWrite(LED_BUILTIN, HIGH);  // turn the LED on (HIGH is the voltage level)
  delay(1000);                      // wait for a second
  digitalWrite(LED_BUILTIN, LOW);   // turn the LED off by making the voltage LOW
  delay(1000);                      // wait for a second
}

/*
 * 30 Days - Lost in Space
 * Day 3 - I'm Worried About Your Battery Levels
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * A light that is always on is also always drawing power, and right now your
 * battery power is limited.  Let's find a way to control your light so that
 * we can turn it off when it's not needed, and save battery power that you'll
 * be needing in the days ahead.
 *
 * Alex Eschenauer
 * David Schmidt
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - if statement (https://www.arduino.cc/reference/en/language/structure/control-structure/if/)
 * - else control structure (https://www.arduino.cc/reference/en/language/structure/control-structure/else/)
 * - comparison operator == (https://www.arduino.cc/reference/en/language/structure/comparison-operators/equalto/)
 * - digitalRead() (https://www.arduino.cc/reference/en/language/functions/digital-io/digitalread/)
 *
 * Parts and electronics concepts introduced in this lesson.
 * - Dual Inline Package (DIP) switches.
 * - Resistors
 */

#include "Arduino.h"  // include information about our HERO

#define CABIN_LIGHTS_PIN 12        // Control our lander's lights using the HERO's pin 12
#define CABIN_LIGHTS_SWITCH_PIN 2  // Connect our light switch to pin 2

// setup() gets called ONCE when our sketch is first run (after upload, when power is
// restored, or when the HERO's reset button is pressed)
void setup() {
  pinMode(CABIN_LIGHTS_PIN, OUTPUT);        // Set light control pin as an OUTPUT
  pinMode(CABIN_LIGHTS_SWITCH_PIN, INPUT);  // Since we read from the switch, this pin is an INPUT
}

// After setup() is executed once the loop() function is called.  Every time it completes it
// is immediately called again, over and over again.
void loop() {
/*
  // First version of our loop.  It works, but could be shorter, more efficient and
  // more understandable.  Commented out but left in to show how we can incrementally
  // improve our code.

  byte switch_setting;

  switch_setting = digitalRead(CABIN_LIGHTS_SWITCH_PIN);   // Read state of light switch

  if (switch_setting == HIGH) {
    digitalWrite(CABIN_LIGHTS_PIN, HIGH);  // if switch is ON then turn on our lander's light
  }

  if (switch_setting == LOW) {
    digitalWrite(CABIN_LIGHTS_PIN, LOW);  // if switch is OFF then turn off lander's light
  }
*/

/*
  // Second version of our loop.  Better.  Define the variable and set it in the same statement
  // and then use the else statement to show that we should always execute ONE of our two
  // actions.

  byte switch_setting = digitalRead(CABIN_LIGHTS_SWITCH_PIN);

  if (switch_setting == HIGH) {
    digitalWrite(CABIN_LIGHTS_PIN, HIGH);  // Switch is ON, turn on our lander's light
  } else {
    digitalWrite(CABIN_LIGHTS_PIN, LOW);  // Switch is OFF, turn off lander's light
  }
*/

  // Final version!  Since we only use our value once, just do our digitalRead once and
  // remove the (now unnecessary) variable.  Clean, fast and less likely to allow bugs
  // to be introduced.

  // Each time loop() begins digitalRead() reads the input pin attached to the switch and
  // compares the value read to HIGH (switch is ON)
  if (digitalRead(CABIN_LIGHTS_SWITCH_PIN) == HIGH) {
    digitalWrite(CABIN_LIGHTS_PIN, HIGH);  // Switch is ON, turn on our lander's light
  } else {
    digitalWrite(CABIN_LIGHTS_PIN, LOW);  // Switch is OFF, turn off lander's light
  }
}

/*
 * 30 Days - Lost in Space
 * Day 4 - Cabin Lighting
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * In addition to our cabin lights we have lights in the storage room and even some
 * exterior lights.  Let's extend our previous project by adding the others and use
 * all three switches on our DIP switch module.  Each time through our loop() code we'll
 * check each switch, and set the corresponding light's state appropriately.
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - const: Better than #define for defining constants that do not change
 * - byte: A data type representing an unsigned 8 bit integer (values from 0 to 255)
 *         Equivalent to "unsigned char" or "uint8_t" which are sometimes seen.
 *
 * Parts and electronics concepts introduced in this lesson.
 * - Use of breadboard "power rails" to allow us to use one 5V and one GND pin on
 *   HERO to connect to multiple components on our breadboard.
 */

#include "Arduino.h"  // include information about our HERO

/*
 * #define vs. const
 *
 * Until now we have been using #define to define our constants.  When the C language
 * was first created that was the only way to define constants.  However, because
 * of the way #define operates there were instances where the use of #define can
 * cause and hide bugs in programs.
 *
 * Becasuse of this, the language maintainers added a new C commands named "const".
 * For most Arduino programs it operates much the same, though it does contain some
 * additional type information that can help communicate how it is to be used.
 *
 * You will see both used in Arduino code and libraries.  However the general
 * language calls for preferring the use of "const" over using #define.  Our first
 * sketches have used #define so that you are familiar with them and see how they
 * work, but from this lesson on we will be using the preferred "const" expression
 * to define our constants.
 *
 * Here, on Day 4 we will show *both* versions, with the #define version commented
 * out to prevent compile errors.  This will help you learn the difference between
 * them.  After today the sketches will only use the preferred "const" versions.
 */

// Each lander light will be controlled using a different pin on our HERO.
// We will use three different color LEDs to make it more clear which switch
// controls which light.

/*
 * The "const" declaration adds another word that will indicate what type of value
 * is to be represented.  Since pins are small numbers they fit into a "byte", which
 * is an unsigned integer value that can hold values from 0 to 255.
 *
 * Other types you may sometimes see in various Arduino code are "uint8_t" or
 * "unsigned char" which are the same as "byte".  We will use the term "byte"
 * in our lessons to indicate 8 bit unsigned integers.
 */
// #define CABIN_LIGHTS_PIN 10             // pin controlling the cabin lights
// #define STORAGE_LIGHTS_PIN 11           // pin controlling the storage lights
// #define COCKPIT_LIGHTS_PIN 12           // pin controlling the exterior lights
const byte CABIN_LIGHTS_PIN = 10;    // pin controlling the cabin lights
const byte STORAGE_LIGHTS_PIN = 11;  // pin controlling the storage lights
const byte COCKPIT_LIGHTS_PIN = 12;  // pin controlling the exterior lights

// We will use a different input pin for each of our DIP switches and
// we'll label them using the color of the LED that each switch will control.
// #define CABIN_LIGHTS_SWITCH_PIN 2             // cabin lights controlled by switch 1
// #define STORAGE_LIGHTS_SWITCH_PIN 3           // storage lights controlled by switch 2
// #define COCKPIT_LIGHTS_SWITCH_PIN 4           // exterior lights controlled by switch 3
const byte CABIN_LIGHTS_SWITCH_PIN = 2;    // cabin lights controlled by switch 1
const byte STORAGE_LIGHTS_SWITCH_PIN = 3;  // storage lights controlled by switch 2
const byte COCKPIT_LIGHTS_SWITCH_PIN = 4;  // exterior lights controlled by switch 3

// the setup function runs once when you press reset or power the board
void setup() {
  // Configure our LED control pins as OUTPUT pins
  pinMode(CABIN_LIGHTS_PIN, OUTPUT);    // pin controlling the cabin lights
  pinMode(STORAGE_LIGHTS_PIN, OUTPUT);  // pin controlling the storage lights
  pinMode(COCKPIT_LIGHTS_PIN, OUTPUT);  // pin controlling the exterior lights

  // Configure the switch pins as INPUT pins
  pinMode(CABIN_LIGHTS_SWITCH_PIN, INPUT);    // pin connected to switch 1 (cabin lights)
  pinMode(STORAGE_LIGHTS_SWITCH_PIN, INPUT);  // pin connected to switch 2 (storage lights)
  pinMode(COCKPIT_LIGHTS_SWITCH_PIN, INPUT);  // pin connected to switch 3 (exterior lights)
}

// Each time through loop() we will check each switch in turn and set each light's
// state appropriately.
void loop() {
  // Control cabin lights based on setting on switch 1
  if (digitalRead(CABIN_LIGHTS_SWITCH_PIN) == HIGH) {  // if switch is on (HIGH voltage)
    digitalWrite(CABIN_LIGHTS_PIN, HIGH);              // turn on LED by providing HIGH voltage (5v)
  } else {
    digitalWrite(CABIN_LIGHTS_PIN, LOW);  // turn off LED by setting output to LOW (zero volts)
  }

  // Control storage lights based on setting on switch 2
  if (digitalRead(STORAGE_LIGHTS_SWITCH_PIN) == HIGH) {  // if switch is on (HIGH voltage)
    digitalWrite(STORAGE_LIGHTS_PIN, HIGH);              // turn on LED by providing HIGH voltage (5v)
  } else {
    digitalWrite(STORAGE_LIGHTS_PIN, LOW);  // turn off LED by setting output to LOW (zero volts)
  }

  // Control exterior lights based on setting on switch 3
  if (digitalRead(COCKPIT_LIGHTS_SWITCH_PIN) == HIGH) {  // if switch is on (HIGH voltage)
    digitalWrite(COCKPIT_LIGHTS_PIN, HIGH);              // turn the LED on (HIGH is the voltage level)
  } else {
    digitalWrite(COCKPIT_LIGHTS_PIN, LOW);  // turn off LED by setting output to LOW (zero volts)
  }
}

/*
 * 30 Days - Lost in Space
 * Day 7 - We still need to keep an eye on this
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Now we will use the circuit from Day 6 and use the value read from the photoresistor
 * to simulate charging our lander's battery.  Our battery is currently drained
 * (current level is 0) and we will stop charging once the battery is full.
 *
 * Alex Eschenauer
 * David Schmidt
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - "+=" operator.
 * - defining our own functions.
 *
 * Parts and electronics concepts introduced in this lesson.
 * - No new parts as this sketch uses the same circuit as Day 6
 */

// Explicitly include Arduino.h
#include "Arduino.h"

// Our photoresistor will give us a reading of the current light level on this analog pin
const byte PHOTORESISTOR_PIN = A0;  // Photoresistor analog pin

// Use an unsigned, 16 bit value (0 - 65535) for maximum battery capacity
const unsigned int BATTERY_CAPACITY = 50000;  // Maximum battery capacity

void setup() {
  pinMode(PHOTORESISTOR_PIN, INPUT);  // Input current light level from photoresistor

  Serial.begin(9600);  // Initialize Serial Monitor to 9600 baud
}

// Use global here because this variable is accessed by both loop() and our custom
// function.  (In later lessons we will show how to avoid globals.)
unsigned int battery_level = 0;  // Current battery charge level (set to 0 first time)

/*
 * Each time through our loop() we read the current light level from the photoresistor
 * and add that to our current battery level to simulate charging our battery.
 *
 * We then display current charge level on the Serial Monitor.
 */
void loop() {

  // Display battery information on the Serial Monitor
  if (battery_level < BATTERY_CAPACITY) {  // If battery is not fully charged..
    /*
     * Here we introduce a new arithmetic operator, "+=".
     * When you wish to add a value to an existing variable you *could* write it like
     * "value = value + additional;".  But the Arduino C++ language allows you to avoid
     * the duplication.  The += operator allows us to add to an existing variable value.
     *
     * In the following statement we will add our current light level to our existing
     * battery level.
     */
    battery_level += analogRead(PHOTORESISTOR_PIN);  // read light level and add to battery level
    if (battery_level > BATTERY_CAPACITY) {          // If this would make charge over 100%...
      battery_level = BATTERY_CAPACITY;              // ...set current level to maximum capacity.
    }
  }

  /*
   * Previously we have only used functions included in the Arduino C++ Language.  Here
   * we demonstrate how we can use our own functions.  This keeps our main code cleaner
   * and easier to understand.  All you need to know here is that this new function prints
   * the current charge level on the Serial Monitor.
   *
   * If you need to know the details you can examine the full function declaration following
   * our loop() code.
   */
  printBatteryChargeLevel();  // Display current charge percentage on Serial Monitor

  delay(100);
}

/*
 * This is where our own function is defined to display the current battery charge
 * level on the Serial Monitor.
 *
 * This function takes no parameters and returns no values (indicated by the "void" preceeding the name).
 *
 * If the battery is not fully charged yet we then print the current battery percentage
 * to the Serial Monitor.
 *
 * If the battery is fully charged we display that to the serial monitor.
 */
void printBatteryChargeLevel() {
  if (battery_level < BATTERY_CAPACITY) {  // if not fully charged
    // Percentage of charge is current level divided by capacity, multiplied by 100 to get a percentage.
    Serial.print(((double)battery_level / (double)BATTERY_CAPACITY) * 100);  // display charge % to Serial Monitor
    Serial.println("%");
  } else {
    Serial.println("FULLY CHARGED");  // ...indicate fully charged on Serial Monitor
  }
}

/*
 * 30 Days - Lost in Space
 * Day 8 - Adding some color to this dark place
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Previously we have used different color LEDs with our HERO, but when we require
 * more output, or desire a color different from the available colors we use a more
 * flexible "RGB LED".  RGB LEDs have a red, a green and a blue LED packaged into a
 * single LED package.  By using something called Pulse Width Modulation (PWM) we
 * can vary the intensity of each LED and come up a wide variety of colors.
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - analogWrite(): Used to control a PWM pin, giving a variable intensity
 * - Passing variables into functions
 *
 * Parts and electronics concepts introduced in this lesson.
 * - Common Cathode (single grounded pin) RGB LED.
 */

// Explicitly include Arduino.h
#include "Arduino.h"

/*
 * Each color in an RGB LED is controlled with a different pin on our HERO board.
 *
 * NOTE: Only pins 3, 5, 6, 9, 10 and 11 on the HERO board support PWM which is
 *       indicated on the board by preceding those pin numbers on the HERO board
 *       with a tilde ('~') character.  Only those pins support PWM and analogWrite().
 */
const byte RED_PIN = 11;    // PWM pin controlling the red leg of our RGB LED
const byte GREEN_PIN = 10;  // PWM pin ccontrolling the green leg of our RGB LED
const byte BLUE_PIN = 9;    // PWM pin ccontrolling the blue leg of our RGB LED

/*
 * Define a set of constants to represent 4 different brightness levels for our
 * RGB LED using PWM pins and analogWrite().  PWM can set values ranging from 0
 * to 255 which we will demonstrate by adding 64 (roughly 1/4 of that range) to
 * each preceding value.
 *
 * NOTE: this also demonstrates that our constants can be computed using an expression
 *       that includes any previouly defined constant.  However, the expression cannot
 *       include variables or values that could change during execution.
 */
const byte OFF = 0;                 // Selected color is OFF
const byte DIM = 64;                // Selected color is 1/4 intensity
const byte BRIGHTER = DIM + 64;     // Selected color is 1/2 intensity
const byte BRIGHT = BRIGHTER + 64;  // Selected color is 3/4 intensity
const byte BRIGHTEST = 255;         // Selected color is maximum intensity (255)

// We can change this constant here, in one place, to change how long each color is displayed.
const unsigned int COLOR_DELAY = 500;  // show each color for 500 milliseconds

void setup() {
  // Set each of our PWM pins as OUTPUT pins
  pinMode(RED_PIN, OUTPUT);
  pinMode(GREEN_PIN, OUTPUT);
  pinMode(BLUE_PIN, OUTPUT);
}

// Each time through loop() we display some of the color variations available
// using an RGB LED.
void loop() {
  // First demonstrate our different PWM levels by slowly brightening our red LED
  displayColor(OFF, OFF, OFF);  // OFF!
  delay(COLOR_DELAY);
  displayColor(DIM, OFF, OFF);  // Display red LED at 1/4 intensity
  delay(COLOR_DELAY);
  displayColor(BRIGHTER, OFF, OFF);  // Display red LED at 1/2 intensity
  delay(COLOR_DELAY);
  displayColor(BRIGHT, OFF, OFF);  // Display red LED at 3/4 intensity
  delay(COLOR_DELAY);
  displayColor(BRIGHTEST, OFF, OFF);  // Display red LED at FULL intensity
  delay(COLOR_DELAY);

  // Display our other two LED colors at half intensity
  displayColor(OFF, BRIGHT, OFF);  // Display the green LED
  delay(COLOR_DELAY);
  displayColor(OFF, OFF, BRIGHT);  // Display the blue LED
  delay(COLOR_DELAY);

  // Now show various colors (at half intensity) by mixing our three colors
  displayColor(BRIGHT, BRIGHT, OFF);  // Display yellow by mixing red and green LEDs
  delay(COLOR_DELAY);
  displayColor(OFF, BRIGHT, BRIGHT);  // Display cyan by mixing green and blue LEDs
  delay(COLOR_DELAY);
  displayColor(BRIGHT, OFF, BRIGHT);  // Display magenta by mixing red and blue LEDs
  delay(COLOR_DELAY);

  // Display all of our LEDs to get white.
  displayColor(BRIGHT, BRIGHT, BRIGHT);  // white
  delay(COLOR_DELAY);
}

/*
 * displayColor() is a function that accepts three parameters representing the desired
 * intensity for each of the LEDs in the RGB LED.
 *
 * Each parameter passed must have a type (here we match what analogWrite() will use) and
 * a name to be used inside the function to refer to the parameter.  The parameters can all
 * be included on a single line like:
 * void displayColor( byte red_intensity, byte green_intensity, byte blue_intensity) {
 * 
 * However, if we display each parameter on it's own line we can add a comment to each
 * for additional clarity.
 */
void displayColor(
  byte red_intensity,    // red LED intensity (0-255)
  byte green_intensity,  // green LED intensity (0-255)
  byte blue_intensity    // blue LED intensity (0-255)
) {
  analogWrite(RED_PIN, red_intensity);      // Set red LED intensity using PWM
  analogWrite(GREEN_PIN, green_intensity);  // Set green LED intensity using PWM
  analogWrite(BLUE_PIN, blue_intensity);    // Set blue LED intensity using PWM
}

/*
 * 30 Days - Lost in Space
 * Day 9 - A Better Way to Do Things
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Now that we know how to measure our battery charging rate and we know how to display
 * multiple colors with the RGB LED, let's combine those two concepts to display different
 * colors as our battery charges to give a good indication of our current battery state.
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - float:   Variable type for decimal numbers that include a decimal point
 * - else if: Control structure for making multiple if decisions together
 *
 * Parts and electronics concepts introduced in this lesson.
 */

// Explicitly include Arduino.h
#include "Arduino.h"

// Our photoresistor will give us a reading of the current light level on this analog pin
const byte PHOTORESISTOR_PIN = A0;  // Photoresistor analog pin

// RGB LED pins
const byte RED_PIN = 11;    // pin controlling the red leg of our RGB LED
const byte GREEN_PIN = 10;  // pin ccontrolling the green leg of our RGB LED
const byte BLUE_PIN = 9;    // pin ccontrolling the blue leg of our RGB LED

const unsigned long BATTERY_CAPACITY = 50000;  // Maximum battery capacity

/*
 * Display a color on our RGB LED by providing an intensity for
 * our red, green and blue LEDs.
 */
void displayColor(
  byte red_intensity,    // red LED intensity (0-255)
  byte green_intensity,  // green LED intensity (0-255)
  byte blue_intensity    // blue LED intensity (0-255)
) {
  analogWrite(RED_PIN, red_intensity);      // write red LED intensity using PWM
  analogWrite(GREEN_PIN, green_intensity);  // write green LED intensity using PWM
  analogWrite(BLUE_PIN, blue_intensity);    // write blue LED intensity using PWM
}

void setup() {
  // Declare the RGB LED pins as outputs:
  pinMode(RED_PIN, OUTPUT);
  pinMode(GREEN_PIN, OUTPUT);
  pinMode(BLUE_PIN, OUTPUT);

  // Start serial monitor
  Serial.begin(9600);
}

void loop() {
  // Use static because we need this variable to maintain it's value across
  // multiple loop() runs.
  static unsigned long battery_level = 0;  // Current battery charge level (set to 0 first time used)

  battery_level += analogRead(PHOTORESISTOR_PIN);  // Add current "charge amount" to our battery

  // We can't charge the battery higher than it's capacity, set level as full if it goes over
  if (battery_level > BATTERY_CAPACITY) {
    battery_level = BATTERY_CAPACITY;
  }

  /*
   * IMPORTANT NOTE:
   * If you perform an operation using integer arithemetic each value is not
   * automatically converted to a floating point (decimal) number.
   *
   * In the calculation below, if we divide the integer battery value by the
   * integer battery capacity (battery_level / BATTERY_CAPACITY) then the result
   * would ALWAYS be 0, even if that 0 gets converted afterwards to a float (0.0).
   *
   * To avoid this, we use the "(float)" declaration before each of our values to
   * instruct the compiler to FIRST convert the value to floating point and then
   * perform the calculation using floating point math.
   *
   * If our current_battery_level is less than the battery capacity the initial
   * calculation gives us a number from 0.0 to 1.0.  We then multiple by 100 to
   * get a percentage value from 0.0 up to 100.0.
   */

  // Compute battery charge percentage from our function
  float percentage = ((float)battery_level / (float)BATTERY_CAPACITY) * 100;

  if (percentage >= 50.0) {     // battery level is OK, display green
    displayColor(0, 128, 0);  // display green
  } else if (percentage >= 25.0 && percentage < 50.0) {
    displayColor(128, 80, 0);  // display yellow-ish/amber for early warning
  } else {                     // Level must be less than 25%, display "pulsating" red
    // To pulsate the red light we briefly turn the LED off and then display red, giving it
    // a pulsating effect.
    displayColor(0, 0, 0);    // Turn off our LED
    delay(20);                // ...and delay briefly
    displayColor(128, 0, 0);  // then display red
  }
  Serial.print(percentage);  // Display our floating point percentage (like 12.34) WITHOUT a newline
  Serial.println("%");       // then display the percent sign ("%") with a newline.

  delay(100);  // Delay 1/10 of a second so displayed values don't scroll too fast
}

/*
 * 30 Days - Lost in Space
 * Day 12 - Can you hear us?
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Today we will use the Keypad from Day 11 to control musical TONES using a
 * small speaker.  To do this we will show how to take the characters returned
 * by the Keypad library and convert them to musical notes played by our speaker.
 * Tones will play until changed or stopped (by pressing the 'D' button at the
 * bottom right of our 4x4 button matrix)
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - libraries: Code provided by others that we can use in our sketches
 * - char type: Represents a single character like 'A', 'd', '4' or '*'.
 * - arrays:    Variables of the same type arranged as a list where each item
 *              can be accessed using an index.  Arrays can be one dimensional
 *              like a list (with one index) or two dimensional like a spreadsheet
 *              table with rows and columns (using row and column indexes).
 * - for loop:  Used to repeately perform actions.
 *
 * Parts and electronics concepts introduced in this lesson.
 */

// Explicitly include Arduino.h
#include "Arduino.h"

// Include Keypad library
#include <Keypad.h>

const byte ROWS = 4;
const byte COLS = 4;

const byte ROW_PINS[ROWS] = { 5, 4, 3, 2 };
const byte COL_PINS[COLS] = { 6, 7, 8, 9 };

char BUTTONS[ROWS][COLS] = {
  { '1', '2', '3', 'A' },  // 1st row
  { '4', '5', '6', 'B' },  // 2nd row
  { '7', '8', '9', 'C' },  // 3rd row
  { '*', '0', '#', 'D' }   // 4th row
};

Keypad myAwesomePad = Keypad(makeKeymap(BUTTONS), ROW_PINS, COL_PINS, ROWS, COLS);

const unsigned int TONES[ROWS][COLS] = {
  // a frequency tone for each button
  { 31, 93, 147, 208 },
  { 247, 311, 370, 440 },
  { 523, 587, 698, 880 },
  { 1397, 2637, 3729, 0 }  // Use frequency of 0 for bottom right key to end tone.
};

const byte BUZZER_PIN = 10;  // pin 10 drives the buzzer

void setup() {
  Serial.begin(9600);  // Begin monitoring via the serial monitor
}


void loop() {
  char button_character = myAwesomePad.waitForKey();  // Wait for a button to be pressed

  /*
   * For loops:
   * for() has three parts.  Each is part is :
   *              START - operations performed when loop starts
   *              CONDITION - evaluate this condition as a boolean and stop loop
   *                          when false
   *              STEP - operations performed every time for loop ends
   *
   * NOTE: you will often see the short variable names "i", "j" and "k" used
   *       for variables in the for statement.  Those particular letters are used
   *       mostly for historical reasons going back to the FORTRAN language, but
   *       the variables in loops tend to be short in order to keep the for command
   *       readable.  The short names also remind you when used that they change
   *       each time through the loop.
   */
  unsigned int tone_frequency = 0;  // Frequency to use for tone (default to 0, no tone)
  for (byte i = 0; i < ROWS; i++) {
    for (byte j = 0; j < COLS; j++) {
      if (button_character == BUTTONS[i][j]) {  // found it, get the corresponding tone
        tone_frequency = TONES[i][j];
      }

    }  // end j loop
  }    // end i loop

  Serial.print("Key: ");  //   send the button_character to serial monitor...
  Serial.print(button_character);
  Serial.print("   Freq: ");
  Serial.println(tone_frequency);

  /*
   * The tone() function plays a tone until stopped.  The code continues to run as the tone plays.
   */
  if (tone_frequency > 0) {                // If tone frequency greater than 0...
    tone(BUZZER_PIN, tone_frequency);  // ...then play the tone at that frequency until stopped
  } else {
    Serial.println("Stop tone");
    noTone(BUZZER_PIN);  // Stop pressed (tone frequency of 0) so stop any tone playing
  }
}

/*
 * 30 Days - Lost in Space
 * Day 13 - HERO Security 101
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Playing tones was fun, but now it's time to get back to business.  Let's use
 * the 4x4 button keypad input a Personal Identification Number (PIN) to unlock
 * access to the lander's control panel.
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - return:  Used by functions to return a single value and return immediately
 *            to the caller of the function.
 * - boolean type: bool is used for a value that can be "true" or "false"
 *                 NOTE: when testing values for true/false the value 0 is considered
 *                       "false" and any non-zero value is considered "true".
 *
 * Parts and electronics concepts introduced in this lesson.
 */

// Explicitly include Arduino.h
#include "Arduino.h"

// Include Keypad library#include <Keypad.h>
#include <Keypad.h>

// Our HERO keypad has 4 rows, each with 4 columns.
const byte ROWS = 4;
const byte COLS = 4;

const byte PIN_LENGTH = 4;    // PIN code is 4 button presses
char current_pin[PIN_LENGTH] = { '0', '0', '0', '0' }; // Initial PIN is four zeros.

// Define what characters will be returned by each button
const char BUTTONS[ROWS][COLS] = {
  { '1', '2', '3', 'A' },
  { '4', '5', '6', 'B' },
  { '7', '8', '9', 'C' },
  { '*', '0', '#', 'D' }
};

// Define row and column pins connected to the keypad
const byte ROW_PINS[ROWS] = { 5, 4, 3, 2 };
const byte COL_PINS[COLS] = { 6, 7, 8, 9 };

Keypad heroKeypad = Keypad(makeKeymap(BUTTONS), ROW_PINS, COL_PINS, ROWS, COLS);

const byte BUZZER_PIN = 10;  // pin 10 drives the buzzer

void setup() {
  pinMode(BUZZER_PIN, OUTPUT);

  Serial.begin(9600);  // Begin monitoring via the serial monitor
  delay(200);          // Delay a brief period to let things settle before displaying prompt.
  Serial.println("Press * to enter new PIN or # to access the system.");
}

void loop() {
  char button_character = heroKeypad.waitForKey();

  // Serial.println(button_character);
  tone(BUZZER_PIN, 880, 100);

  if (button_character == '#') {  // button to access system
    bool access_allowed = validatePIN();
    if (access_allowed) {
      Serial.println("Welcome, authorized user. You may now begin using the system.");
    } else {
      Serial.println("Access Denied.");
      Serial.println("\nPress * to enter new PIN or # to access the system.");
    }
  }

  if (button_character == '*') {  // button to change PIN
    bool access_allowed = validatePIN();

    if (access_allowed) {
      Serial.println("Welcome, authorized user. Please Enter a new PIN: ");

      for (int i = 0; i < PIN_LENGTH; i++) {
        button_character = heroKeypad.waitForKey();
        tone(BUZZER_PIN, 880, 100);

        current_pin[i] = button_character;
        Serial.print("*");
      }

      Serial.println();  // add new line after last asterisk so next message is on next line
      Serial.println("PIN Successfully Changed!");
    } else {
      Serial.println("Access Denied. Cannot change PIN without the old or default.");
      Serial.println("\nPress * to enter new PIN or # to access the system.");
    }
  }
}

/*
 * This function prompts the user to enter a PIN and returns true or false depending
 * on whether the PIN matches our saved PIN.
 *
 * NOTE: this function introduces the concept of a function that returns a single
 *       value.  First, we must indicate what type of value that will be returned
 *       in the initial function declaration.  The "bool" at the beginning of
 *       the declaration indicates that this function will return a "boolean" value
 *       of either true or false.
 */

bool validatePIN() {
  Serial.println("Enter PIN to continue.");

  for (int i = 0; i < PIN_LENGTH; i++) {
    char button_character = heroKeypad.waitForKey();
    tone(BUZZER_PIN, 880, 100);

    if (current_pin[i] != button_character) {
      Serial.println();  // start next message on new line
      Serial.print("WRONG PIN DIGIT: ");
      Serial.println(button_character);
      return false;  // return false and exit function
    }
    Serial.print("*");
  }

  Serial.println();  // add new line after last asterisk so next message is on next line
  Serial.println("Device Successfully Unlocked!");
  return true;
}

/*
 * 30 Days - Lost in Space
 * Day 14 - Advanced Security Panel
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Time to enhance our security system, taking it from functional to fabulous.  We'll
 * add in our RGB LED to give us visual feedback and also expand the tones that play
 * to give us audible feedback as you enter your PIN.
 *
 * IMPORTANT NOTE: The wiring for this sketch builds on the Day 13 wiring. But the
 *                 addition of the RGB LED requires us to MOVE some of the Day 13
 *                 wires.  This is because the RGB LED only works when connected to
 *                 pins that support Pulse Width Modulation (PWM).  HERO pins that
 *                 support PWM have a tilde ('~') preceeding their pin numbers.
 *
 *                 If you look at the Day 13 diagrams you see that we used PWM pins
 *                 for the keypad and buzzer, leaving only one available.  Pins 12
 *                 and 13 are still available so we'll move the wires on pins 9 and 10
 *                 (PWM pins) to 12 and 13.
 *
 *                 Pin 13 is also used while the Arduino IDE is uploading sketches, and
 *                 if you connect the buzzer to THAT pin you get noise every time you
 *                 upload a new sketch (try it!).  So the buzzer will now be on pin 12
 *                 and the keypad wire on pin 9 will move to pin 13.
 *
 *                 Because we used constants, we only need to make two small changes
 *                 from the Day 13 sketch instead of hunting down and changing each use.
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - complex logic with multiple devices
 *
 * Parts and electronics concepts introduced in this lesson.
 * - Changing wiring when particular pins (PWM) are required for added components.
 * - Tone() and PWM analogWrite() cannot both operate at the same time.
 */

// Explicitly include Arduino.h
#include "Arduino.h"

// Include Keypad library
#include <Keypad.h>

// Our HERO keypad has 4 rows, each with 4 columns.
const byte ROWS = 4;
const byte COLS = 4;

const byte PIN_LENGTH = 4;                           // PIN code is 4 button presses
char password[PIN_LENGTH] = { '0', '0', '0', '0' };  // Initial password is four zeros.

// Define what characters will be returned by each button
const char BUTTONS[ROWS][COLS] = {
  { '1', '2', '3', 'A' },
  { '4', '5', '6', 'B' },
  { '7', '8', '9', 'C' },
  { '*', '0', '#', 'D' }
};

// Define row and column pins connected to the keypad
const byte ROW_PINS[ROWS] = { 5, 4, 3, 2 };
const byte COL_PINS[COLS] = { 6, 7, 8, 13 };  // NOTE wire moved from Day 13's sketch to pin 13

// Create our keypad object from the keypad configuration above
Keypad heroKeypad = Keypad(makeKeymap(BUTTONS), ROW_PINS, COL_PINS, ROWS, COLS);

const byte BUZZER_PIN = 12;  // NOTE that pin 12 drives the buzzer now

const byte RED_PIN = 11;    // PWM pin controlling the red leg of our RGB LED
const byte GREEN_PIN = 10;  // PWM pin ccontrolling the green leg of our RGB LED
const byte BLUE_PIN = 9;    // PWM pin ccontrolling the blue leg of our RGB LED

void setup() {
  pinMode(RED_PIN, OUTPUT);
  pinMode(GREEN_PIN, OUTPUT);
  pinMode(BLUE_PIN, OUTPUT);

  // Since we start out "locked", we initially display a red color.
  displayColor(128, 0, 0);

  Serial.begin(9600);  // Begin monitoring via the serial monitor
  Serial.println("Press * to set new password or # to access the system.");
}

void loop() {
  char button_character = heroKeypad.getKey();  // Wait for a button press and save character

  // The '#' button unlocks our console
  if (button_character == '#') {          // Button to access system
    giveInputFeedback();                  // Short beep with blue light
    bool access_allowed = validatePIN();  // Have user enter PIN to allow access

    if (access_allowed) {
      Serial.println("Welcome, authorized user. You may now begin using the system.");
    } else {
      Serial.println("Access Denied.");
      Serial.println("\nPress * to enter new PIN or # to access the system.");
    }
  }

  // The '*' allows the user to enter a new PIN after entering current PIN for security
  if (button_character == '*') {          // Button to change password
    giveInputFeedback();                  // Short beep with blue light
    bool access_allowed = validatePIN();  // Have user enter PIN to allow access

    if (access_allowed) {
      displayColor(128, 80, 0);  // Display yellow LED while entering a NEW PIN
      Serial.println("Welcome, authorized user. Please Enter a new password: ");

      // Use a for() loop that runs once for each PIN character.  Each character read
      // replaces a character in our original PIN.
      for (int i = 0; i < PIN_LENGTH; i++) {
        password[i] = heroKeypad.waitForKey();  // replace PIN character with new character
        // NOTE: After the LAST button press we will give Success feedback, but up to the
        //       last character we simply give input feedback.  Since Array indices start
        //       at 0, this if() statement will be true for all but the LAST character of
        //       the new PIN.
        if (i < (PIN_LENGTH - 1)) {
          giveInputFeedback();
          displayColor(128, 80, 0);  // override color
        }

        Serial.print("*");
      }

      Serial.println();  // add new line after last asterisk so next message is on next line
      Serial.println("PIN Successfully Changed!");
      giveSuccessFeedback();  // TADA sound and green light for successful PIN change
    } else {
      Serial.println("Access Denied. Cannot change PIN without entering current PIN first.");
      Serial.println("\nPress * to enter new PIN or # to access the system.");
    }
  }
}

// Enter PIN and return false for bad PIN or true for good PIN
bool validatePIN() {
  Serial.println("Enter PIN to continue.");

  for (int i = 0; i < PIN_LENGTH; i++) {
    char button_character = heroKeypad.waitForKey();

    if (password[i] != button_character) {
      giveErrorFeedback();  // Error sound and red light
      Serial.println();     // start next message on new line
      Serial.print("WRONG PIN DIGIT: ");
      Serial.println(button_character);
      return false;  // return false and exit function
    }
    // Give normal input feedback for all but the LAST character
    if (i < (PIN_LENGTH - 1)) {
      giveInputFeedback();  // Short beep and blue LED
    }
    Serial.print("*");
  }

  giveSuccessFeedback();  // PIN matched - TADA! sound with green LED
  Serial.println();       // add new line after last asterisk so next message is on next line
  Serial.println("Device Successfully Unlocked!");
  return true;
}

// Display a color by providing Red, Green and Blue intensities (0-255)
void displayColor(byte red_intensity, byte green_intensity, byte blue_intensity) {
  analogWrite(RED_PIN, red_intensity);      // Set red LED intensity using PWM
  analogWrite(GREEN_PIN, green_intensity);  // Set green LED intensity using PWM
  analogWrite(BLUE_PIN, blue_intensity);    // Set blue LED intensity using PWM
}

/*
 * NOTE:
 * Both the PWM functions and tone() functions use some of the same HERO hardware
 * for their functions.  If the RGB LED is on while a tone is played it will flicker
 * or diplay other colors.  Because of this, we turn off the LED while a tone is
 * being played and restore it immediately afterwards.
 */

// A recognized button was pressed.  Give short beep and blue LED
void giveInputFeedback() {
  displayColor(0, 0, 0);  // Turn off LED while playing tone
  tone(BUZZER_PIN, 880, 200);
  delay(200);               // Delay while tone is playing because tone() returns immediately
  displayColor(0, 0, 128);  // Restore blue LED
}

// A matching PIN has been entered or a new PIN has been accepted.
// Play TADA! sound and display green LED
void giveSuccessFeedback() {
  displayColor(0, 0, 0);  // Turn off LED while playing tone
  tone(BUZZER_PIN, 300, 200);
  delay(200);  // Delay while tone is playing because tone() returns immediately

  tone(BUZZER_PIN, 500, 500);
  delay(500);  // Delay while tone is playing because tone() returns immediately
  displayColor(0, 128, 0); // Display green LED
}

// Bad PIN entered.  Play descending tone and display red LED
void giveErrorFeedback() {
  displayColor(0, 0, 0);  // Turn off LED while playing tone
  tone(BUZZER_PIN, 300, 200);
  delay(200);  // Delay while tone is playing because tone() returns immediately

  tone(BUZZER_PIN, 200, 500);  // Frequency = 200Hz, Duration = 200ms
  delay(500);  // Delay while tone is playing because tone() returns immediately
  displayColor(128, 0, 0);  // Display red LED
}

/*
 * 30 Days - Lost in Space
 * Day 16 - A Fancy New Display
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Sound and light gives us some good feedback from our HERO, but what about
 * when we need numbers and the Serial Console isn't available?  Today we
 * introduce a 4-digit 7-segment display (TM1637).  This is mostly for numbers,
 * like a counter or perhaps a clock display, but with some imagination we can
 * also show some characters.
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - Binary notation (0b00000001)
 * - logical OR
 * - 
 *
 * Parts and electronics concepts introduced in this lesson.
 * - TM1637 4-digit 7-segment display
 */

// Explicitly include Arduino.h
#include "Arduino.h"

/*
 * Please refer to the lesson and lesson videos for instructions on how to
 * load the TM1637 library into your Arduino IDE before you use it for the
 * first time.
 *
 * In order to use the TM1637 library we include the file "TM1637Display.h".
 */
#include <TM1637Display.h>

// all_on pins connected to the TM1637 display
const byte CLK_PIN = 6;
const byte DIO_PIN = 5;

// Create display object of type TM1637Display:
TM1637Display lander_display = TM1637Display(CLK_PIN, DIO_PIN);

/*
 * The TM1637 library takes an array of 4 bytes to represent each of the 4 display
 * digits.  Within each byte, bit 0 is segment A, bit 1 is segment B etc.  A zero
 * indicates the segment is off, a 1 bit indicates the segment is on.
 *
 * NOTE: To show the individual bits in each byte we will use BINARY number notation
 *       consisting of a "0b" followed by eight bits that can be either 0 or 1 (ex.
 *       0b01010101).
 */

// Create array that turns all segments on:
const byte all_on[] = { 0b11111111,
                        0b11111111,
                        0b11111111,
                        0b11111111 };

/*
 * A 7-segment display is shaped like an "8" and has 7 segments (A through G) that can be
 * lit up. The diagram below shows the placement of each of the segments.
 *
 *   A
 * F   B
 *   G
 * E   C
 *   D
 *
 * You can set the individual segments per digit to spell words or create other symbols.
 * The TM1637 library provides constants for each segment on the display.  If you hover
 * your mouse over each of these constants you can see that each defines a byte with only
 * one bit set to 1.  SEG_A = 0b00000001, SEG_B = 0b00000010, etc.
 *
 * The Arduino C++ language uses the '|' operator to do a "bitwise or" between values.  It
 * takes each corresponding bits in two values and the output is 1 if *either* or both of the
 * corresponding bits is 1.  If both corresponding bits are 0 then the corresponding bit is
 * set to 0.
 *
 * In other words:
 * 0  0  1  1    operand1
 * 0  1  0  1    operand2
 * ----------
 * 0  1  1  1    (operand1 | operand2) - returned result
 */

 // By turning on selected segments we can display *some* alphabetic characters.
 // Here we spell out the word "dOnE".
const byte done[] = {
  SEG_B | SEG_C | SEG_D | SEG_E | SEG_G,          // d
  SEG_A | SEG_B | SEG_C | SEG_D | SEG_E | SEG_F,  // O
  SEG_C | SEG_E | SEG_G,                          // n
  SEG_A | SEG_D | SEG_E | SEG_F | SEG_G           // E
};

void setup() {
  lander_display.setBrightness(7);  // Configure the display brightness (0-7):
}

void loop() {
  // Clear the display (all segments off)
  lander_display.clear();
  delay(1000);

  // Light up all segments of the display
  lander_display.setSegments(all_on);
  delay(1000);

  // Clear the display (all segments off)
  lander_display.clear();
  delay(1000);

  /*
   *
   * Microwave after a power outage
   * Blinking 12:00.  The .showNumberDecEx() function has an additional parameter to turn
   * on the ':' after the 2nd digit.  This works well for time displays.
   *
   * The second parameter can also be used to control dots between digits if the
   * display has them.  In our case, the HERO display only has the colon.
   *
   * Dot/Colon enable. The argument is a bitmask, with each bit corresponding to a dot
   *        between the digits (or colon mark, as implemented by each module). i.e.
   *        For displays with dots between each digit:
   *        * 0.000 (0b10000000)
   *        * 00.00 (0b01000000)
   *        * 000.0 (0b00100000)
   *        * 0.0.0.0 (0b11100000)
   *        For displays with just a colon:     <== This is true for the HERO display
   *        * 00:00 (0b01000000)
   *        For displays with dots and colons colon:
   *        * 0.0:0.0 (0b11100000)
   */
  for (int i = 0; i < 4; i++) {
    lander_display.showNumberDecEx(1200, 0b01000000);
    delay(500);
    lander_display.clear();
    delay(500);
  }

  // Show counter including negative sign for negative numbers
  // NOTE: negative numbers cannot be less than -999 since the negative sign
  //       uses the left most digit of the display.
  for (int i = -100; i <= 100; i++) {
    lander_display.showNumberDec(i);
    delay(50);
  }
  delay(1000);

  // Clear the display (all segments off)
  lander_display.clear();
  delay(1000);

  // Display the message "dOnE"
  lander_display.setSegments(done);

  delay(10000);  // Delay 10 seconds and then repeat our demo.
}

