/*
 * 30 Days - Lost in Space
 * Day 18 - The Surface Seems So Much Closer
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * It's time to examine how we can control our lander's ascent from our watery
 * depths.  For this we'll use a new device from our repair kit; the Rotary
 * Encoder.  We will turn it's dial to raise (or re-lower?) our lander from
 * it's current resting spot on the sea floor.
 *
 * Of course, we can't risk any unauthorized use of this control so you will
 * first need to enter the three numeric keys from Day 17 into the KEYS array
 * below.  If the correct keys aren't entered then the controls will remain
 * locked.
 *
 * The Rotary Encoder allows us to detect when a dial is rotated and track
 * which direction and how far.  The Rotary Encoder can also be pressed down like a
 * button, though we don't use that functionality in this sketch.
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - Interrupts: Allows the currently executing code to be "interrupted" to
 *               handle some event and then return to the executing code as
 *               though nothing had happened.
 * - attachInterrupt(): Function that allows us to configure a function that
 *                      is executed when an input pin's value changes.
 * - digitalPinToInterrupt(): Converts a pin number to an internal HERO interrupt
 *                            number.
 * NOTE: The HERO board only supports interrupts on pins 2 and 3.
 *
 * Parts and electronics concepts introduced in this lesson.
 * - Rotary Encoder: Allows sketch to respond to rotational input (clockwise or
 *   counter-clockwise).  Also can provide a button input when pressed down.
 */

// Explicitly include Arduino.h
#include "Arduino.h"

// Include TM1637 library file
#include <TM1637Display.h>

// Include BasicEncoder library file
#include <BasicEncoder.h>

// Controls will be locked unless the correct keys from Day 17 are added here.
const unsigned int KEYS[] = {
  0,  // Replace '0' with first key from Day 17
  0,  // Replace '0' with second key from Day 17
  0   // Replace '0' with third key from Day 17
};

// The Rotary Encoder will be used to control our lander's depth underwater using
// interrupts (explained below).  Since the HERO board only supports interrupts on
// pins 2 and 3, we MUST use those pins for rotary encoder inputs.
const byte DEPTH_CONTROL_CLK_PIN = 2;  // HERO interrupt pin connected to encoder CLK input
const byte DEPTH_CONTROL_DT_PIN = 3;   // HERO interrupt pin connected to encoder DT input

// Create BasicEncoder instance for our depth control (which initializes counter to 0)
BasicEncoder depth_control(DEPTH_CONTROL_CLK_PIN, DEPTH_CONTROL_DT_PIN);

// Define the display connection pins:
const byte DEPTH_GAUGE_CLK_PIN = 6;
const byte DEPTH_GAUGE_DIO_PIN = 5;

// Our TM1637 4-digit 7-segment display will be used as our "depth gauge".
TM1637Display depth_gauge = TM1637Display(DEPTH_GAUGE_CLK_PIN, DEPTH_GAUGE_DIO_PIN);

const byte BLINK_COUNT = 3;  // blink depth gauge this many times for attention.

// Create array that turns all segments on:
// const byte data[] = { 0xff, 0xff, 0xff, 0xff };

// You can set the individual segments per digit to spell words or create other symbols:
const byte done[] = {
  SEG_B | SEG_C | SEG_D | SEG_E | SEG_G,          // d
  SEG_A | SEG_B | SEG_C | SEG_D | SEG_E | SEG_F,  // O
  SEG_C | SEG_E | SEG_G,                          // n
  SEG_A | SEG_D | SEG_E | SEG_F | SEG_G           // E
};

const byte nope[] = {
  SEG_C | SEG_E | SEG_G,                          // n
  SEG_A | SEG_B | SEG_C | SEG_D | SEG_E | SEG_F,  // O
  SEG_A | SEG_B | SEG_E | SEG_F | SEG_G,          // P
  SEG_A | SEG_D | SEG_E | SEG_F | SEG_G           // E
};

// Our lander is currently this deep underwater so this is what is initially
// shown on our "depth gauge" (4-digit 7-segment display).
const int INITIAL_DEPTH = -60;

// Alert user when we rise above this depth
const int ALERT_DEPTH_1 = -40;  // First alert depth
const int ALERT_DEPTH_2 = -20;  // Second alert depth
const int SURFACE_DEPTH = 0;    // Depth of the sea surface

void setup() {
  // Setup Serial Monitor
  Serial.begin(9600);
  delay(1000);

  depth_gauge.setBrightness(7);  // Set depth gauge brightness to max (values 0-7)

  if (keysAreValid()) {
    depth_gauge.showNumberDec(INITIAL_DEPTH);  // Display our initial depth on our depth gauge.
  } else {
    depth_gauge.setSegments(nope);  // Display "nOPE" on display to show key error
    Serial.println("ERROR: Invalid keys.  Please enter the 3 numeric keys from Day 17");
    Serial.println("       in order in the KEYS array at the start of this sketch.");
    while (true)
      ;
  }

  /*
   * Our HERO board allow executing code to be "interrupted" when the value of a pin
   * changes.  These two commands allow us to provide code that is executed whenever
   * the level of a configured pin is changed (as occurs when the rotary encoder is
   * turned).
   *
   * When the rotary encoder is turned (in either direction) our "updateEncoder" function
   * will be executed.  When updateEncoder() completes the code resumes at exactly the
   * place where it was interrupted.
   */
  // Call Interrupt Service Routine (ISR) updateEncoder() when any high/low change
  // is seen on A (DEPTH_CONTROL_CLK_PIN) interrupt  (pin 2), or B (DEPTH_CONTROL_DT_PIN) interrupt (pin 3)
  attachInterrupt(digitalPinToInterrupt(DEPTH_CONTROL_CLK_PIN), updateEncoder, CHANGE);
  attachInterrupt(digitalPinToInterrupt(DEPTH_CONTROL_DT_PIN), updateEncoder, CHANGE);
}

void loop() {
  if (depth_control.get_change()) {  // If the depth control value has changed since last check
    // The rotary encoder library always sets the initial counter to 0, so we will always
    // add our initial depth to the counter to properly track our current depth.
    int current_depth = INITIAL_DEPTH + depth_control.get_count();

    // We cannot go deeper than the sea floor where the lander sits, so reset the counter
    // if the user tries to go deeper than our initial depth.
    if (current_depth < INITIAL_DEPTH) {
      current_depth = INITIAL_DEPTH;
      depth_control.reset();
    }

    // Display our current depth on our digital depth gauge
    depth_gauge.showNumberDec(current_depth);
    delay(50);

    // Since BasicEncoder can be clicked multiple times per loop via interrupts we
    // track when counter has passed milestones THIS time through the loop.  We do
    // by testing whether the previous counter was less than the milestone and current
    // counter is greater or equal.

    /*
     * Explorer, to prevent stress on our lander we should not rise too rapidly.
     * To keep you alert we will blink our depth gauge when our depth goes past
     * predefined levels.
     *
     * Because the rotary encoder might be rotated more than one click between
     * loops() we will write our code so that we can detect when one of our warning
     * levels has been reached OR PASSED.
     *
     * We do this by tracking the depth reached on the previous loop() execution
     * and then comparing this to our current depth to see if we crossed one of
     * our warning depths.
     */

    // Depth from the previous loop, initialized to our initial depth first time
    // through the loop().
    static int previous_depth;  // Depth from our previous loop().

    // If we crossed our first level then blink our depth to alert our explorer.
    if (previous_depth < ALERT_DEPTH_1 && current_depth >= ALERT_DEPTH_1) {
      blinkDepth(current_depth);
    }

    // If we crossed our second level then blink our depth to alert our explorer.
    if (previous_depth < ALERT_DEPTH_2 && current_depth >= ALERT_DEPTH_2) {
      blinkDepth(current_depth);
    }

    // We have reached the surface!  Blink "dOnE" on our depth gauge
    if (current_depth >= SURFACE_DEPTH) {
      for (int i = 0; i < BLINK_COUNT; i++) {
        depth_gauge.clear();
        delay(300);
        depth_gauge.setSegments(done);  // Display "dOnE"
        delay(300);
      }
    }
    previous_depth = current_depth;  // save current depth for next time through the loop
  }
}

// Validate that the explorer has entered the correct key values
// This is deliberately cryptic so it's not apparent what the 3 keys are.
bool keysAreValid() {
  unsigned int i = 0155;
  if (KEYS[0]!=0b10110*'+'/051)i+=2;
  if (KEYS[1]==uint16_t(0x8f23)/'4'-0537)i|=0200;
  if (KEYS[2]!=0x70b1/021-0b1001)i+=020;
  return !(18^i^0377);32786-458*0b00101010111;
}

// Blink our current depth off and on to alert the user.
void blinkDepth(int depth) {
  for (int i = 0; i < BLINK_COUNT; i++) {
    depth_gauge.clear();  // clear depth gauge
    delay(300);
    depth_gauge.showNumberDec(depth);  // display current depth
    delay(300);
  }
}

/*
 * This is our interrupt handler function that we configured in setup().
 * Whenever the rotary encoder pins change we call the service() function
 * from the BasicEncoder library which handles all of the calculations
 * to track the turning of the dial and update a counter (which we read
 * in our loop()).
 */
void updateEncoder() {
  depth_control.service();  // Call BasicEncoder library .service()
}

/*
 * 30 Days - Lost in Space
 * Day 19 - The Surface Seems So Much Closer
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Moving on from Day 18, let's get our ship moving towards the surface today!
 *
 * As we tested our code from Day 18 we noticed a few things we can do to make
 * our ascent even safer.  The Day 18 sketch allowed us to ascend faster than is
 * safe, so let's limit the RATE of ascent to a slow rate.
 *
 * In addition, we'll add a buzzer to our curcuit to give us an audible alert if
 * our rise rate is faster than what is safe.
 *
 * Lastly, it turns out our safety stop depths are when we're 50% towards the
 * surface and 75% of the way to the surface.  Let's make this sketch track our
 * rise as a percentage of the way from our starting depth.
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - integer percentages without using floating point
 *
 * Parts and electronics concepts introduced in this lesson.
 * - 
 */

// Explicitly include Arduino.h
#include "Arduino.h"

// Include TM1637 library file
#include <TM1637Display.h>

// Include BasicEncoder library file
#include <BasicEncoder.h>

// Controls will be locked unless the correct keys from Day 17 are added here.
const unsigned int KEYS[] = {
  0,  // Replace '0' with first key from Day 17
  0,  // Replace '0' with second key from Day 17
  0   // Replace '0' with third key from Day 17
};

// The Rotary Encoder will be used to control our lander's depth underwater using
// interrupts (explained below).  Since the HERO board only supports interrupts on
// pins 2 and 3, we MUST use those pins for rotary encoder inputs.
const byte DEPTH_CONTROL_CLK_PIN = 2;  // HERO interrupt pin connected to encoder CLK input
const byte DEPTH_CONTROL_DT_PIN = 3;   // HERO interrupt pin connected to encoder DT input

// Create BasicEncoder instance for our depth control (which initializes counter to 0)
BasicEncoder depth_control(DEPTH_CONTROL_CLK_PIN, DEPTH_CONTROL_DT_PIN);

// Define the display connection pins:
const byte DEPTH_GAUGE_CLK_PIN = 6;
const byte DEPTH_GAUGE_DIO_PIN = 5;

// Our TM1637 4-digit 7-segment display will be used as our "depth gauge".
TM1637Display depth_gauge = TM1637Display(DEPTH_GAUGE_CLK_PIN, DEPTH_GAUGE_DIO_PIN);

const byte BUZZER_PIN = 10;   // Alert buzzer

const byte BLINK_COUNT = 3;   // blink depth gauge this many times for attention.

// You can set the individual segments per digit to spell words or create other symbols:
const byte done[] = {
  SEG_B | SEG_C | SEG_D | SEG_E | SEG_G,          // d
  SEG_A | SEG_B | SEG_C | SEG_D | SEG_E | SEG_F,  // O
  SEG_C | SEG_E | SEG_G,                          // n
  SEG_A | SEG_D | SEG_E | SEG_F | SEG_G           // E
};

const byte nope[] = {
  SEG_C | SEG_E | SEG_G,                          // n
  SEG_A | SEG_B | SEG_C | SEG_D | SEG_E | SEG_F,  // O
  SEG_A | SEG_B | SEG_E | SEG_F | SEG_G,          // P
  SEG_A | SEG_D | SEG_E | SEG_F | SEG_G           // E
};

const byte hold[] = {
  SEG_B | SEG_C | SEG_E | SEG_F | SEG_G,  // H
  SEG_C | SEG_D | SEG_E | SEG_G,          // o
  SEG_D | SEG_E | SEG_F,                  // L
  SEG_B | SEG_C | SEG_D | SEG_E | SEG_G,  // d
};

// Our lander is currently this deep underwater so this is what is initially
// shown on our "depth gauge" (4-digit 7-segment display).
const int INITIAL_DEPTH = -60;

// Alert user when we have risen 50% and 75% of the way up.
const int ALERT_DEPTH_1 = INITIAL_DEPTH * 0.50;  // First alert when 50% of the way up
const int ALERT_DEPTH_2 = INITIAL_DEPTH * 0.25;  // Second alert when 75% of the way up (25% of original depth)

const int SURFACE_DEPTH = 0;    // Depth of the sea surface

void setup() {
  pinMode(BUZZER_PIN, OUTPUT);

  // Setup Serial Monitor
  Serial.begin(9600);
  delay(1000);

  depth_gauge.setBrightness(7);  // Set depth gauge brightness to max (values 0-7)

  if (keysAreValid()) {
    depth_gauge.showNumberDec(INITIAL_DEPTH);  // Display our initial depth on our depth gauge.
  } else {
    depth_gauge.setSegments(nope);  // Display "nOPE" on display to show key error
    Serial.println("ERROR: Invalid keys.  Please enter the 3 numeric keys from Day 17");
    Serial.println("       in order in the KEYS array at the start of this sketch.");
    while (true)
      ;
  }

  // Call Interrupt Service Routine (ISR) updateEncoder() when any high/low change
  // is seen on A (DEPTH_CONTROL_CLK_PIN) interrupt  (pin 2), or B (DEPTH_CONTROL_DT_PIN) interrupt (pin 3)
  attachInterrupt(digitalPinToInterrupt(DEPTH_CONTROL_CLK_PIN), updateEncoder, CHANGE);
  attachInterrupt(digitalPinToInterrupt(DEPTH_CONTROL_DT_PIN), updateEncoder, CHANGE);
}

const unsigned int LOOP_DELAY = 200;  // Delay in ms between loop() executions.

void loop() {
  // Depth from the previous loop, initialized to our initial depth first time
  // through the loop().  When changed it retains it's value between loop executions.
  static int previous_depth = INITIAL_DEPTH;  // Depth from our previous loop(), 

  if (depth_control.get_change()) {  // If the depth control value has changed since last check
    // The rotary encoder library always sets the initial counter to 0, so we will always
    // add our initial depth to the counter to properly track our current depth.
    int current_depth = INITIAL_DEPTH + depth_control.get_count();

    // Compute our percentage of the way up.
    // NOTE: We can avoid using slower floating point arithmetic by first multiplying the
    //       current depth by 100.  This is a trick we often use when the final result
    //       doesn't require any decimal portion.
    byte rise_percentage = 100 - ((current_depth * 100) / INITIAL_DEPTH);

    // Rising too quickly could stress the hull of our lander.  Because of this we will
    // play an alert if the lander is instructed to rise faster than 1 meter ever time
    // through our loop.
    int rise_rate = current_depth - previous_depth;
    if (rise_rate > 1) {
      tone(BUZZER_PIN, 80, LOOP_DELAY);
    }

    // We cannot go deeper than the sea floor where the lander sits, so reset the counter
    // if the user tries to go deeper than our initial depth.
    if (current_depth < INITIAL_DEPTH) {
      current_depth = INITIAL_DEPTH;
      depth_control.reset();
    }

    // Display our current depth on our digital depth gauge
    depth_gauge.showNumberDec(current_depth);

    // Since BasicEncoder can be clicked multiple times per loop via interrupts we
    // track when counter has passed milestones THIS time through the loop.  We do
    // by testing whether the previous counter was less than the milestone and current
    // counter is greater or equal.

    // If we crossed our first alert level then flash "hold" on the display.
    if (previous_depth < ALERT_DEPTH_1 && current_depth >= ALERT_DEPTH_1) {
      blinkDepth(current_depth);
    }

    // If we crossed our second alert level then then flash "hold" on the display.
    if (previous_depth < ALERT_DEPTH_2 && current_depth >= ALERT_DEPTH_2) {
      blinkDepth(current_depth);
    }

    // We have reached the surface!  Blink "dOnE" on our depth gauge and play a
    // happy completion tone.
    if (current_depth >= SURFACE_DEPTH) {
      // Play 'tada!' tune on our buzzer.
      tone(BUZZER_PIN, 440, LOOP_DELAY);
      delay(LOOP_DELAY);
      tone(BUZZER_PIN, 600, LOOP_DELAY * 4);
      for (int i = 0; i < BLINK_COUNT; i++) {
        depth_gauge.clear();
        delay(300);
        depth_gauge.setSegments(done);  // Display "dOnE"
        delay(300);
      }
    }
    previous_depth = current_depth;  // save current depth for next time through the loop
  }
  delay(LOOP_DELAY);
}

// Validate that the explorer has entered the correct key values
// This is deliberately cryptic so it's not apparent what the 3 keys are.
bool keysAreValid() {
  unsigned int i = 0155;
  if (KEYS[0]!=0b10110*'+'/051)i+= 2;
  if (KEYS[1]==uint16_t(0x8f23)/'4'-0537)i|= 0200;
  if (KEYS[2]!=0x70b1/021-0b1001)i+=020;
  return !(18^i^0377);32786-458*0b00101010111;
}

// Blink our current depth off and on to alert the user.
void blinkDepth(int depth) {
  for (int i = 0; i < BLINK_COUNT; i++) {
    depth_gauge.setSegments(hold);
    delay(300);
    depth_gauge.showNumberDec(depth);  // display current depth
    delay(300);
  }
}

// Interrupt Service Routine (ISR).  Let BasicEncoder library handle the rotator changes
void updateEncoder() {
  depth_control.service();  // Call BasicEncoder library .service()
}

/*
 * 30 Days - Lost in Space
 * Day 21 - Hello New World!
 *
 * For safe liftoff we're going to need to see and react to more information than
 * can be displayed on our 4 digit display or with LEDs.  Luckily our repair kit
 * contains just the thing, a small monochrome Organic LED display.
 *
 * This display has 8,128 tiny LEDs arranged in 64 rows of 128 pixels each.  Now, as
 * I'm sure you've noticed, we do NOT have 8,128 pins on our HERO board, but never
 * fear Explorer, people back in the 2020's were pretty clever and came up with a
 * solution.
 *
 * Instead of having one pin for every LED, The HERO will use two pins to send and
 * receive messages with our OLED display and will instruct the display which pixels
 * to light up using a special "language" (or "protocol") named I2C ("eye-squared-see").
 *
 * The HERO board uses pins A5 and A4 for I2C communications so we will wire those two
 * pins to our display along with power and ground, giving us a four wire connection
 * for displaying messages or pictures on our new display.
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - I2C communications.
 * - Computer character fonts
 * - U8g2 graphics library for monochrome displays
 * - Logical Not operator ('!')
 * - clearBuffer()/sendBuffer() method for OLED display updates
 *
 * Parts and electronics concepts introduced in this lesson.
 * - SH1106 monochrome 128x64 pixel OLED display.
 * - HERO I2C pins (A5 and A4)
 */

// Explicitly include Arduino.h
#include "Arduino.h"

/*
 * Refer to the Day 21 lesson for instructions on how to install the U8g2
 * library into the Arduino IDE.  We will use this library to display messages
 * on our OLED display.
 *
 * Extensive documentation for this library can be found at https://github.com/olikraus/u8g2
 * for those wanting to dive deeper, but we will explain all of the functions
 * used in these lessons.
 */
#include <U8g2lib.h>  // Include file for the U8g2 library.

/*
 * The U8g2 library supports many different types of display.  It does this by
 * having a different "constructor" for each.  A constructor is used to create
 * the "handle" that we use to access the libray code.  In this case, our handle
 * will be named "lander_display".
 *
 * The documentation for this library lists all of the displays supported along
 * with the corresponding constructors and options.  This constructor is for our
 * SH1106, 128x64 pixel generic display.  The "_F_" indicates that we will use
 * a full-sized graphics buffer and the clearBuffer()/sendBuffer() methods to
 * update the entire display at once. The "HW_I2C" indicates that we will be using
 * I2C communications with this display.
 */
U8G2_SH1106_128X64_NONAME_F_HW_I2C lander_display(U8G2_R0, /* reset=*/U8X8_PIN_NONE);

void setup(void) {
  Serial.begin(9600);
  delay(1000);
  lander_display.begin();  // Initialize our display

  // Select a font to use for character display
  // The library supports hundreds of different fonts which can be found at
  // https://github.com/olikraus/u8g2/wiki/fntlistall
  lander_display.setFont(u8g2_font_ncenB08_tr);  // choose a suitable font

  // Uncomment the next line if your display shows the text upside down.
  // lander_display.setDisplayRotation(U8G2_R2);
}

void loop(void) {
  // Save the number of vertical pixels required for the tallest character
  // in the current font.  This is used later to properly position text on
  // our display.
  byte font_height = lander_display.getMaxCharHeight();

  lander_display.clearBuffer();  // clear the internal memory

  /*
   * Even though we will only be displaying text in this lesson, our display is a
   * graphics display.  Text can be displayed at ANY point on the display so the
   * library has a setCursor() function to locate the first character to be displayed.
   *
   * By default, the cursor position is set to the bit at the lower-left of the
   * first character, but here we set this to be the UPPER-left of the first
   * character which makes it easier to position our first line of text on the top
   * of our display.
   */
  lander_display.setFontPosTop();

  // Title line for our display
  drawCenteredString(0, "Exploration Lander");

  // Display our "Hello World!" message on line 2 (moving down "font_height" bits)
  drawCenteredString(font_height, "Hello World!");

  /*
   * We will blink a message centered in the remainder of the display.  However, with
   * this display we cannot clear just part of the display.  The entire display is copied
   * over from the buffer every time we call sendBuffer().  So, the easiest way to cause
   * some text to blink is to simply add it to the display every other time through our
   * loop() and set the delay at the end of the loop to the on/off time.
   *
   * To do this we will set a static variable (which keeps it's value between loop() executions)
   * and only write this message when the variable is true.  Then, at the end of the loop we
   * toggle the variable to the opposite value.
   */
  static bool blink_on = true;
  if (blink_on) {
    /*
    * Now let's center our starting message in the remaining space.  To do this we'll take the
    * height of our display, subtract the height of our title lines and divide by two.  We'll then
    * instruct the library to center the text vertically from our starting Y position.
    */
    byte centered_y = (font_height * 2) + ((lander_display.getDisplayHeight() - (font_height * 2)) / 2);

    // This statement instructs the graphics library that the Y coordinate used to position
    // the text will be halfway between the top and bottom of the text.
    lander_display.setFontPosCenter();  // Draw text with centered Y coordinate
    drawCenteredString(centered_y, "Stand by");
  }
  // A boolean value can be changed between it's two states by setting it to the opposite
  // state using the "logical not".  Not true = false.  Not false = true.
  // This would be read as "blink on equals not blink on".
  blink_on = !blink_on;   // toggle value of blink_on between true and false

  // Nothing is displayed on our display until the buffer is sent to the display, below.
  lander_display.sendBuffer();  // transfer internal memory to the display
  delay(500);   // Delay for blink effect
}

// Use the .drawStr() method to draw the current string centered in
// the current display.
byte drawCenteredString(byte y, char *string) {
  byte centered_x = (lander_display.getDisplayWidth() - lander_display.getStrWidth(string)) / 2;
  lander_display.drawStr(centered_x, y, string);
}

/*
 * 30 Days - Lost in Space
 * Day 22 - Display Panel Details
 *
 * Even our new OLED display is a bit small if we have large amounts of
 * information to display.  But this new display isn't limited to JUST
 * text!  It is a 128x64 pixel display and we can turn any of them on/off
 * to display whatever we like, including graphics.
 *
 * Today we'll run a "readiness check" on our new display to test out its
 * full capabilities.
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - 
 * - 
 * - 
 *
 * Parts and electronics concepts introduced in this lesson.
 * - 
 */

// Explicitly include Arduino.h
#include "Arduino.h"
#include "Wire.h"

/*
 * Extensive documentation for this library can be found at https://github.com/olikraus/u8g2
 * for those wanting to dive deeper, but we will explain all of the functions
 * used in these lessons.
 */
#include <U8g2lib.h>  // Include file for the U8g2 library.

// Construct our lander_display handle using the same constructor from Day 21
U8G2_SH1106_128X64_NONAME_F_HW_I2C lander_display(U8G2_R0, /* reset=*/U8X8_PIN_NONE);

void setup(void) {
  lander_display.begin();  // Initialize display library

  // Uncomment the next line if your display shows the text upside down.
  // lander_display.setDisplayRotation(U8G2_R2);
}

/*
 * For our main loop() we will cycle through each test page, displaying
 * 8 frames for each test (which allows animation on each page).
 *
 * Rather than use two variables, one to track the page and one to track
 * the frame, we will demonstrate the use of the "bitshift" operators (">>"
 * and "<<") in conjunction with the bitwise and" to use a single variable.
 *
 * While this method is less clear, it is sometimes used when memory is very
 * tight since it uses less data storage.
 */
void loop(void) {
  const byte TEST_PAGE_COUNT = 13;
  for (unsigned int display_frame = 0; display_frame < (TEST_PAGE_COUNT * 8); display_frame++) {
    lander_display.clearBuffer();  // clear the internal memory

    // setCursor() will set the x/y location of the upper left bit of each string
    lander_display.setFont(u8g_font_6x10);
    lander_display.setFontRefHeightExtendedText();
    lander_display.setFontPosTop();

    // y_offset is current Y coordinate below all previously drawn content
    byte y_offset = 0;    // start at top of display

    // Title line for our display displayed on each screen
    drawCenteredString(0, 0, "Exploration Lander");  // Center title at top of display

    // To leave the title above each display we add the maximum character height of
    // our current font to the current y_offset.
    y_offset += lander_display.getMaxCharHeight();  // maximum height of current font

    // If you'd like to just view a single page just uncomment the next two lines and
    // set the page desired in the first line.
    // const byte DISPLAY_PAGE = 12;
    // display_frame = (display_frame & 7) | (DISPLAY_PAGE << 3);

    // Now display the appropriate page for our current display_frame.
    // Since each page is displayed 8 times we shift the display_frame right
    // by 3 bits, which is a FAST way of dividing it by 8.
    switch (display_frame >> 3) {
      // The frame number for each page is contained in the rightmost 3
      // bits of the current display_frame.  So here we remove the page
      // number by using a bitwise AND to remove all but the last three bits.
      case 0: display_test_ready(y_offset, display_frame & 0b00000111); break;
      case 1: display_test_box_frame(y_offset, display_frame & 0b00000111); break;
      case 2: display_test_circles(y_offset, display_frame & 0b00000111); break;
      case 3: display_test_r_frame(y_offset, display_frame & 0b00000111); break;
      case 4: display_test_string(y_offset, display_frame & 0b00000111); break;
      case 5: display_test_line(y_offset, display_frame & 0b00000111); break;
      case 6: display_test_triangle(y_offset, display_frame & 0b00000111); break;
      case 7: display_test_ascii_1(y_offset); break;
      case 8: display_test_ascii_2(y_offset); break;
      case 9: display_test_extra_page(y_offset, display_frame & 0b00000111); break;
      case 10: display_test_bitmap_modes(y_offset, display_frame & 0b00000111, false); break;
      case 11: display_test_bitmap_modes(y_offset, display_frame & 0b00000111, true); break;
      case 12: display_test_bitmap_overlay(y_offset, display_frame & 0b00000111); break;
    }
    lander_display.sendBuffer();
    delay(100);
  }
}

// Use the .drawStr() method to draw a string in the display centered
// horizontally between the given X coordinate and the maximum X.
// Y coordinate is unchanged and text is displayed relative to the
// current font positioning mode (Top, Center, Bottom).
byte drawCenteredString(byte x, byte y, char *string) {
  byte centered_x = x + ((lander_display.getDisplayWidth() - x) - lander_display.getStrWidth(string)) / 2;
  lander_display.drawStr(centered_x, y, string);
}

const byte LANDER_HEIGHT = 25;    // height of our lander image, in bits
const byte LANDER_WIDTH = 20;     // width of our lander image, in bits

// Draw an image of our lander drawn with frames and triangles
// at location x_location, y_location (relative to the upper left corner).
void display_lander(byte x_location, byte y_location) {
  lander_display.drawFrame(x_location + 7, y_location, 6, 5);        // ship top
  lander_display.drawFrame(x_location + 5, y_location + 4, 10, 20);  // ship center
  lander_display.drawFrame(x_location, y_location + 6, 6, 16);       // left pod
  lander_display.drawFrame(x_location + 14, y_location + 6, 6, 16);  // right pod
  lander_display.drawTriangle(x_location + 2, y_location + 21,
                              x_location, y_location + 25,
                              x_location + 4, y_location + 25);  // left nozzle
  lander_display.drawTriangle(x_location + 18, y_location + 21,
                              x_location + 15, y_location + 25,
                              x_location + 20, y_location + 25);  // right nozzle
}

/////////////////////////////////////////////////////////////////////
// Page 0: Display lander drawing and blinking begin message
void display_test_ready(byte y_offset, byte frame) {
  // Y value halfway between top and bottom of drawable area
  const byte Y_CENTER = y_offset + ((lander_display.getDisplayHeight() - y_offset) / 2);

  // Since our lander drawing's location is set using the upper-left
  // coordinates we will subtract half our drawing's height to center
  // it vertically.
  //
  // We will also shift it right by adding a "padding" amount to the
  // lander's X coordinate.
  const byte LANDER_PADDING = LANDER_WIDTH;   // shift lander right by its width
  const byte LANDER_Y_CENTER = Y_CENTER - (LANDER_HEIGHT / 2);
  display_lander(LANDER_PADDING, LANDER_Y_CENTER);

  // Blink the "ready" message by only displaying it every other frame
  // by extracting the rightmost bit of our frame number and only displaying
  // the message if the bit is 0 (frames 0, 2, 4, 6).
  if ((frame & 0b00000001) == 0) {
    // Determine remaining space to the right of our lander for our message.
    // The lander image extends from its starting X position plus its width.
    const byte X_OFFSET = LANDER_PADDING + LANDER_WIDTH;

    // get the height of each text line since it's used multiple times below
    byte text_height = lander_display.getMaxCharHeight();

    lander_display.setFontPosCenter();  // Y coordinate relative to center of font height
    // Display line 1 on display, one line above center
    drawCenteredString(X_OFFSET, Y_CENTER - text_height, "Begin");

    // Display line 2, vertically centered in space below title
    drawCenteredString(X_OFFSET, Y_CENTER, "Hardware");

    // Display line 3 on display, one line below center
    drawCenteredString(X_OFFSET, Y_CENTER + text_height, "Test");
  }
}

/////////////////////////////////////////////////////////////////////
// Page 1: Display filled and hollow boxes with one moving every frame.

// Here we define constants for our box size and coordinates.  This is
// done so they can be changed in one place, and it also makes it clear
// what the MEANINGS of each number are in the code below.  It changes
// code like:
// .drawBox(5,10,20,10);
// to:
// .drawBox(BOX1_X_OFFSET, y_offset, BOX1_WIDTH, BOX1_HEIGHT);
const byte BOX1_WIDTH = 20;
const byte BOX1_HEIGHT = 10;
const byte BOX1_X_OFFSET = 5;
const byte BOX2_WIDTH = BOX1_WIDTH * 1.5;
const byte BOX2_HEIGHT = BOX1_HEIGHT * .8;
const byte BOX2_X_OFFSET = BOX1_X_OFFSET * 2;
const byte BOX2_Y_OFFSET = BOX1_HEIGHT / 2;

void display_test_box_frame(byte y_offset, byte frame) {
  drawCenteredString(0, y_offset, "drawBox");
  y_offset += lander_display.getMaxCharHeight();  // offset down by font height
  // Draw a filled box at x, y, width, height.
  lander_display.drawBox(BOX1_X_OFFSET, y_offset, BOX1_WIDTH, BOX1_HEIGHT);
  // Draw a second box offset offset and moving right each frame
  lander_display.drawBox(BOX2_X_OFFSET + frame, y_offset + BOX2_Y_OFFSET,
                         BOX2_WIDTH, BOX2_HEIGHT);

  y_offset += BOX2_Y_OFFSET + BOX2_HEIGHT;  // offset down by drawn boxes
  drawCenteredString(0, y_offset, "drawFrame");
  y_offset += lander_display.getMaxCharHeight();  // offset down by font height
  // Draw box frame at x, y, width, height.
  lander_display.drawFrame(BOX1_X_OFFSET, y_offset, BOX1_WIDTH, BOX1_HEIGHT);
  // Draw second box frame offset and moving right each frame
  lander_display.drawFrame(BOX2_X_OFFSET + frame, y_offset + BOX2_Y_OFFSET,
                           BOX2_WIDTH, BOX2_HEIGHT);
}

/////////////////////////////////////////////////////////////////////
// Page 2: Display filled and hollow circles with one moving every frame.

const byte CIRCLE1_RADIUS = 8;
const byte CIRCLE1_DIAMETER = (CIRCLE1_RADIUS * 2) + 1;   // Diameter is (radius * 2) + 1
const byte CIRCLE1_X_OFFSET = CIRCLE1_RADIUS;
const byte CIRCLE2_RADIUS = CIRCLE1_RADIUS - 1;
const byte CIRCLE2_X_OFFSET = CIRCLE1_DIAMETER + CIRCLE2_RADIUS;

void display_test_circles(byte y_offset, byte frame) {
  drawCenteredString(0, y_offset, "drawDisc");
  y_offset += lander_display.getMaxCharHeight();  // offset down by font height
  // Center disc at x, y with radius.
  lander_display.drawDisc(CIRCLE1_X_OFFSET, y_offset + CIRCLE1_RADIUS, CIRCLE1_RADIUS);
  // Draw second (moving) disc 
  lander_display.drawDisc(CIRCLE2_X_OFFSET + frame, y_offset + CIRCLE2_RADIUS, CIRCLE2_RADIUS);

  y_offset += CIRCLE1_DIAMETER;
  drawCenteredString(0, y_offset, "drawCircle");
  y_offset += lander_display.getMaxCharHeight();  // offset down by font height
  // Draw hollow circle at x, y with radius
  lander_display.drawCircle(CIRCLE1_X_OFFSET, y_offset + CIRCLE1_RADIUS, CIRCLE1_RADIUS);
  // Draw second (moving) hollow circle
  lander_display.drawCircle(CIRCLE2_X_OFFSET + frame, y_offset + CIRCLE2_RADIUS, CIRCLE2_RADIUS);
}

/////////////////////////////////////////////////////////////////////
// Page 3: Display filled and hollow boxes with rounded corners

const byte RBOX1_WIDTH = 40;
const byte RBOX1_HEIGHT = 30;
const byte RBOX1_X_OFFSET = 5;
const byte RBOX2_WIDTH = 25;
const byte RBOX2_HEIGHT = 40;
const byte RBOX2_X_OFFSET = RBOX1_X_OFFSET + RBOX1_WIDTH + RBOX1_X_OFFSET;

void display_test_r_frame(byte y_offset, byte frame) {
  drawCenteredString(0, y_offset, "drawRFrame/Box");
  y_offset += lander_display.getMaxCharHeight();  // offset down by font height

  lander_display.drawRFrame(RBOX1_X_OFFSET, y_offset, RBOX1_WIDTH, RBOX1_HEIGHT, frame + 1);
  lander_display.drawRBox(RBOX2_X_OFFSET, y_offset, RBOX2_WIDTH, RBOX2_HEIGHT, frame + 1);
}

/////////////////////////////////////////////////////////////////////
// Page 4: Display text strings, drawing them in different directions

const byte STRING_X_OFFSET = 30;

void display_test_string(byte y_offset, byte frame) {
  byte y_center = y_offset + (lander_display.getDisplayHeight() - y_offset) / 2;

  lander_display.setFontDirection(0);   // left to right
  lander_display.drawStr(STRING_X_OFFSET + frame, y_center, " 0");

  lander_display.setFontDirection(1);   // up to down
  lander_display.drawStr(STRING_X_OFFSET, y_center + frame, " 90");

  lander_display.setFontDirection(2);   // right to left (and upside down)
  lander_display.drawStr(STRING_X_OFFSET - frame, y_center, " 180");

  lander_display.setFontDirection(3);   // down to up
  lander_display.drawStr(STRING_X_OFFSET, y_center - frame, " 270");

  lander_display.setFontDirection(0);   // Restore normal left to right direction
}

/////////////////////////////////////////////////////////////////////
// Page 5: Display lines at different angles

const byte LINE_X_OFFSET = 7;
const byte LINE_Y_MAX = 55;

void display_test_line(byte y_offset, byte frame) {
  drawCenteredString(0, y_offset, "drawLine");
  y_offset += lander_display.getMaxCharHeight();  // offset down by font height

  // Draw lines from x1/y1 to x2/y2, moving x1 each frame.
  lander_display.drawLine(LINE_X_OFFSET + frame, y_offset,
                          40, LINE_Y_MAX);
  lander_display.drawLine(LINE_X_OFFSET + frame * 2, y_offset,
                          60, LINE_Y_MAX);
  lander_display.drawLine(LINE_X_OFFSET + frame * 3, y_offset,
                          80, LINE_Y_MAX);
  lander_display.drawLine(LINE_X_OFFSET + frame * 4, y_offset,
                          100, LINE_Y_MAX);
}

/////////////////////////////////////////////////////////////////////
// Page 6: Display triangles that separate each frame

void display_test_triangle(byte y_offset, byte frame) {
  drawCenteredString(0, y_offset, "drawTriangle");

  y_offset += lander_display.getMaxCharHeight();  // offset down by font height
  lander_display.drawTriangle(14, y_offset + 7,
                              45, y_offset + 20,
                              10, y_offset + 30);
  lander_display.drawTriangle(14 + frame, y_offset + 7 - frame,
                              45 + frame, y_offset + 20 - frame,
                              57 + frame, y_offset + 00 - frame);
  lander_display.drawTriangle(57 + frame * 2, y_offset + 0,
                              45 + frame * 2, y_offset + 20,
                              96 + frame * 2, y_offset + 43);
  lander_display.drawTriangle(10 + frame, y_offset + 30 + frame,
                              45 + frame, y_offset + 20 + frame,
                              96 + frame, y_offset + 43 + frame);
}

/////////////////////////////////////////////////////////////////////
// Page 7: Display characters from first ASCII page

const byte FIRST_PRINTABLE_CHARACTER = 32;  // ASCII character 32 is first printable character
void display_test_ascii_1(byte y_offset) {
  drawCenteredString(0, y_offset, "ASCII page 1");
  y_offset += lander_display.getMaxCharHeight();  // offset down by font height

  // For more characters visible you can uncomment the following line for a smaller font
  // lander_display.setFont(u8g2_font_spleen5x8_mf);
  byte character_width = lander_display.getMaxCharWidth();
  byte column_count = lander_display.getDisplayWidth() / character_width;
  byte row_count = (lander_display.getDisplayHeight() - y_offset) / lander_display.getMaxCharHeight();

  for (byte row = 0; row < row_count; row++) {
    for (byte column = 0; column < column_count; column++) {
      char character_string[2];  // space for character plus null terminator
      byte character_number = FIRST_PRINTABLE_CHARACTER + (row * column_count) + column;
      snprintf(character_string, sizeof(character_string), "%c", character_number);
      lander_display.drawStr(column * character_width,
                             y_offset + (row * lander_display.getMaxCharHeight()),
                             character_string);
    }
  }
}

/////////////////////////////////////////////////////////////////////
// Page 8: Display characters from second ASCII page

void display_test_ascii_2(byte y_offset) {
  drawCenteredString(0, y_offset, "ASCII page 2");
  y_offset += lander_display.getMaxCharHeight();  // offset down by font height

  // For more characters visible you can uncomment the following line for a smaller font
  // lander_display.setFont(u8g2_font_spleen5x8_mf);
  byte character_width = lander_display.getMaxCharWidth();
  byte column_count = lander_display.getDisplayWidth() / character_width;
  byte row_count = (lander_display.getDisplayHeight() - y_offset) / lander_display.getMaxCharHeight();

  for (byte row = 0; row < row_count; row++) {
    for (byte column = 0; column < column_count; column++) {
      char character_string[2];  // space for character plus null terminator
      byte character_number = FIRST_PRINTABLE_CHARACTER + 128 + (row * column_count) + column;
      snprintf(character_string, sizeof(character_string), "%c", character_number);
      lander_display.drawStr(column * character_width,
                             y_offset + (row * lander_display.getMaxCharHeight()),
                             character_string);
    }
  }
}

/////////////////////////////////////////////////////////////////////
// Page 9: Display characters from Unicode font

void display_test_extra_page(byte y_offset, byte frame) {
  drawCenteredString(0, y_offset, "Unicode");
  y_offset += lander_display.getMaxCharHeight();  // offset down by font height

  lander_display.setFont(u8g2_font_unifont_t_symbols);
  lander_display.setFontPosTop();
  lander_display.drawUTF8(0, y_offset, "☀ ☁");
  switch (frame) {
    case 0:
    case 1:
    case 2:
    case 3:
      lander_display.drawUTF8(frame * 3, y_offset + 20, "☂");
      break;
    case 4:
    case 5:
    case 6:
    case 7:
      lander_display.drawUTF8(frame * 3, y_offset + 20, "☔");
      break;
  }
}

