/////////////////////////////////////////////////////////////////////
// Pages 10 and 11: Display bitmap modes (non-transparent / transparent)

void display_test_bitmap_modes(byte y_offset, byte frame, bool transparent) {
  if (!transparent) {
    lander_display.setBitmapMode(false /* solid */);
    drawCenteredString(0, y_offset, "Solid bitmap");
  } else {
    lander_display.setBitmapMode(true /* transparent*/);
    drawCenteredString(0, y_offset, "Transparent bitmap");
  }

  y_offset += lander_display.getMaxCharHeight();  // offset down by font height
  const byte frame_size = CROSS_HEIGHT + 4;
  lander_display.drawBox(0, y_offset,
                         frame_size * 5, frame_size/2);
  lander_display.setDrawColor(0);  // Black
  lander_display.drawXBMP(frame_size * 0.5, y_offset + (frame_size/2)-(CROSS_HEIGHT/2),
                          CROSS_WIDTH, CROSS_HEIGHT, cross_bits);
  lander_display.setDrawColor(1);  // White
  lander_display.drawXBMP(frame_size * 2, y_offset + (frame_size/2)-(CROSS_HEIGHT/2),
                          CROSS_WIDTH, CROSS_HEIGHT, cross_bits);
  lander_display.setDrawColor(2);  // XOR
  lander_display.drawXBMP(frame_size * 3.5, y_offset + (frame_size/2)-(CROSS_HEIGHT/2),
                          CROSS_WIDTH, CROSS_HEIGHT, cross_bits);
  lander_display.setDrawColor(1);   // restore default color

  lander_display.drawStr(frame_size * 0.5, y_offset + frame_size, "Black");
  lander_display.drawStr(frame_size * 2, y_offset + frame_size, "White");
  lander_display.drawStr(frame_size * 3.5, y_offset + frame_size, "XOR");
  if (frame == 7) {
    delay(1000);
  }
}

/////////////////////////////////////////////////////////////////////
// Pages 12: Display bitmap overlay mode

void display_test_bitmap_overlay(byte y_offset, byte frame) {
  byte frame_size = CROSS_FILL_HEIGHT + 4;
  byte frame_padding = 5;

  drawCenteredString(0, y_offset, "Bitmap overlay");

  y_offset += lander_display.getMaxCharHeight();  // offset down by font height
  lander_display.setBitmapMode(false /* solid */);
  lander_display.drawFrame(0, y_offset, frame_size, frame_size);
  lander_display.drawXBMP((frame_size / 2) - (CROSS_FILL_WIDTH / 2),
                          y_offset + (frame_size / 2) - (CROSS_FILL_HEIGHT / 2),
                          CROSS_WIDTH, CROSS_HEIGHT, cross_bits);
  if (frame & 4)
    lander_display.drawXBMP((frame_size / 2) - (CROSS_BLOCK_WIDTH / 2),
                            y_offset + (frame_size / 2) - (CROSS_BLOCK_HEIGHT / 2),
                            CROSS_BLOCK_WIDTH, CROSS_BLOCK_HEIGHT, cross_block_bits);

  lander_display.setBitmapMode(true /* transparent*/);
  lander_display.drawFrame(frame_size + frame_padding, y_offset,
                           frame_size, frame_size);
  lander_display.drawXBMP(frame_size + frame_padding + (frame_size / 2) - (CROSS_FILL_WIDTH / 2),
                          y_offset + (frame_size / 2) - (CROSS_FILL_HEIGHT / 2),
                          CROSS_WIDTH, CROSS_HEIGHT, cross_bits);
  if (frame & 4)
    lander_display.drawXBMP(frame_size + frame_padding + (frame_size / 2) - (CROSS_BLOCK_WIDTH / 2),
                            y_offset + (frame_size / 2) - (CROSS_BLOCK_HEIGHT / 2),
                            CROSS_BLOCK_WIDTH, CROSS_BLOCK_HEIGHT, cross_block_bits);

  lander_display.drawStr(0, y_offset + frame_size, "Solid / transparent");
  if (frame == 7) {
    delay(1000);
  }
}

/*
 * 30 Days - Lost in Space
 * Day 23 - Launch System
 *
 * Even our new OLED display is a bit small if we have large amounts of
 * information to display.  But this new display isn't limited to JUST
 * text!  It is a 128x64 pixel display and we can turn any of them on/off
 * to display whatever we like, including graphics.
 *
 * Today we'll run a "readiness check" on our new display to test out its
 * full capabilities.
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - #define macros
 * - rounding up calculated values
 * - elapsed time without using delay() calls.
 * - firstPage()/nextPage() graphics loop to save memory
 *
 * Parts and electronics concepts introduced in this lesson.
 * - 
 */

// Explicitly include Arduino.h
#include "Arduino.h"
#include "Wire.h"

// Include file for 4 digit - 7 segment display library
#include <TM1637Display.h>

/*
 * Extensive documentation for this library can be found at https://github.com/olikraus/u8g2
 * for those wanting to dive deeper, but we will explain all of the functions
 * used in these lessons.
 */
#include <U8g2lib.h>  // Include file for the U8g2 library.

/*
 * #define macros
 *
 * We started the first few lessons of this course showing how "#define" works since
 * it's still often used, but on Day 4 we introduced the newer and better "const"
 * and have been using it since to define all of our constants.
 *
 * But "#define" *does* have some capabilities that "const" doesn't.  The one we
 * use today is the use of parameters, turning our constant into a simple, in-line
 * function.
 *
 * Since #define performs simple text substitution this method executes faster since
 * it doesn't have any overhead to call and return a function.
 *
 * WARNING: #define macros CAN cause bugs if the variable passed in is used in multiple
 * places in the macro because the text inside the call is simply replaced in the macro.
 *
 * These examples perform a simple calculation returning the minutes or seconds from
 * a number representing milliseconds, rounded UP to the next highest second by adding
 * 999 milliseconds.  This allows our counter to return 00:01 until the instant the
 * counter reaches zero.
 */
#define numberOfMinutes(_milliseconds_) (((_milliseconds_ + 999) / 1000) / 60)
#define numberOfSeconds(_milliseconds_) (((_milliseconds_ + 999) / 1000) % 60)

// Pin connections for our 4 digit counter
#define COUNTER_DISPLAY_CLK_PIN 5
#define COUNTER_DISPLAY_DIO_PIN 4
// Construct counter_display handle.
TM1637Display counter_display(COUNTER_DISPLAY_CLK_PIN, COUNTER_DISPLAY_DIO_PIN);

/*
 * This constructor for our OLED differs from the one used for the previous
 * days, changing the "_F_" to "_2_".  This indicates that instead of using
 * a full sized buffer to draw to our OLED display a smaller, 256 byte buffer
 * will be used along with the firstPage()/nextPage() calls.  This gives us
 * more memory for other variables, though the display may update slower.
 */
U8G2_SH1106_128X64_NONAME_2_HW_I2C lander_display(U8G2_R0, /* reset=*/U8X8_PIN_NONE);

const byte LANDER_HEIGHT = 25;  // height of our lander image, in bits
const byte LANDER_WIDTH = 20;   // width of our lander image, in bits

// Define 7 Segment display values to spell out "dOnE"
const uint8_t DONE[] = {
  SEG_B | SEG_C | SEG_D | SEG_E | SEG_G,          // d
  SEG_A | SEG_B | SEG_C | SEG_D | SEG_E | SEG_F,  // O
  SEG_C | SEG_E | SEG_G,                          // n
  SEG_A | SEG_D | SEG_E | SEG_F | SEG_G           // E
};

// Define amount of time (in milliseconds) to count down.
const unsigned long COUNTDOWN_MILLISECONDS = 5 * 1000;

// *********************************************
void setup() {
  Serial.begin(9600);

  // Configure counter display
  counter_display.setBrightness(7);  // Set maximum brightness (value is 0-7)
  counter_display.clear();           // Clear the display

  // Configure OLED display
  lander_display.begin();                     // Initialize OLED display
  lander_display.setFont(u8g2_font_6x10_tr);  // Set text font
  lander_display.setFontRefHeightText();
  lander_display.setFontPosTop();

  /*
   * Display starting status on our lander's OLED display.
   *
   * The U8g2 library for Arduino uses a technique called "page buffering" to draw on
   * displays connected to microcontrollers with limited RAM. Here's a short explanation
   * of how it works:
   *
   * firstPage(): This function starts the drawing routine. It initializes the buffer with
   *              the first "page" or segment of the display.
   * nextPage(): After drawing the first page, this function is called in a loop. Each call
   *             loads the next segment into the buffer and allows you to draw additional
   *             content. This process repeats until the entire display content is drawn over
   *             multiple pages.
   * Looping: The combination of firstPage() and nextPage() is typically used inside a loop.
   *          The loop continues until nextPage() returns false, indicating that all pages
   *          have been drawn.
   *
   * By drawing the display in segments, the library conserves RAM, making it feasible to use
   * graphics displays with microcontrollers that have limited memory resources.
   */
  lander_display.firstPage();
  do {
    byte y_offset = drawString(0, 0, "Exploration Lander");
    drawString(0, y_offset, "Liftoff Sequence");

    // Status on bottom line of OLED display
    drawString(0, lander_display.getDisplayHeight() - lander_display.getMaxCharHeight(), "Countdown Active");
    // Draw a picture of our lander int bottom right corner
    displayLander(lander_display.getDisplayWidth() - LANDER_WIDTH,
                  lander_display.getDisplayHeight() - LANDER_HEIGHT);
  } while (lander_display.nextPage());

  // blink the countdown on our timer before beginning the countdown
  for (int i = 0; i < 4; i++) {
    counter_display.clear();
    delay(200);
    displayCounter(COUNTDOWN_MILLISECONDS);
    delay(200);
  }
  Serial.println("Countdown started..: ");
}

// *********************************************
void loop() {
  // Initialize static variables first time through loop() that will retain values
  // between loop() executions.
  static unsigned long timeRemaining = COUNTDOWN_MILLISECONDS;
  static unsigned long countdown_start_time = millis();

  Serial.println(timeRemaining);  // Display milliseconds remaining on serial console
  displayCounter(timeRemaining);  // Display minutes:seconds on counter display

  // If timeRemaining has reached 0 display ending values
  if (timeRemaining == 0) {
    Serial.println("Done!!");           // indicate completion on serial console
    counter_display.setSegments(DONE);  // "dOnE" on our counter

    // Now update our OLED display with ending screen using firstPage()/nextPage()
    lander_display.firstPage();
    do {
      // Each time we display a line of text on our display the y_offset
      // is updated to point to the next available point for drawing.
      // Display first two lines
      byte y_offset = drawString(0, 0, "Exploration Lander");
      y_offset = drawString(0, y_offset, "Liftoff ABORTED");

      // Set y_offset to point four lines above bottom of display
      y_offset = lander_display.getDisplayHeight() - (4 * lander_display.getMaxCharHeight());
      // Display last four lines
      y_offset = drawString(0, y_offset, "Thrusters: OFF");
      y_offset = drawString(0, y_offset, "Systems: OFF");
      y_offset = drawString(0, y_offset, "Confirm: OFF");
      drawString(0, y_offset, "Countdown ABORT");
      // Draw a picture of our lander in bottom right corner
      displayLander(lander_display.getDisplayWidth() - LANDER_WIDTH,
                    lander_display.getDisplayHeight() - LANDER_HEIGHT);
    } while (lander_display.nextPage());

    // Stop here by looping forever.
    while (1)
      ;
  }

  // Update our remaining time by subtracting the start time from current
  // execution time (in milliseconds).  If our elapsed time is greater
  // than our countdown time then set remaining time to 0.
  unsigned long elapsed_time = millis() - countdown_start_time;
  if (elapsed_time < COUNTDOWN_MILLISECONDS) {
    timeRemaining = COUNTDOWN_MILLISECONDS - elapsed_time;
  } else {
    timeRemaining = 0;
  }
}

// Display milliseconds as minutes:seconds (MM:SS)
void displayCounter(unsigned long milliseconds) {
  // To display the countdown in mm:ss format, separate the parts
  byte minutes = numberOfMinutes(milliseconds);
  byte seconds = numberOfSeconds(milliseconds);

  // Display the minutes in the first two places, with colon
  counter_display.showNumberDecEx(minutes, 0b01000000, true, 2, 0);
  // This displays the seconds in the last two places
  counter_display.showNumberDecEx(seconds, 0, true, 2, 2);
}

// Draw test on our lander display at x, y, returning new y
// value that is immediately below the new line of text.
byte drawString(byte x, byte y, char *string) {
  lander_display.drawStr(x, y, string);
  return (y + lander_display.getMaxCharHeight());  // return new y_offset on display
}

// Draw an image of our lander drawn with frames and triangles
// at location x_location, y_location (relative to the upper left corner).
void displayLander(byte x_location, byte y_location) {
  lander_display.drawFrame(x_location + 7, y_location, 6, 5);        // ship top
  lander_display.drawFrame(x_location + 5, y_location + 4, 10, 20);  // ship center
  lander_display.drawFrame(x_location, y_location + 6, 6, 16);       // left pod
  lander_display.drawFrame(x_location + 14, y_location + 6, 6, 16);  // right pod
  lander_display.drawTriangle(x_location + 2, y_location + 21,
                              x_location, y_location + 25,
                              x_location + 4, y_location + 25);  // left nozzle
  lander_display.drawTriangle(x_location + 18, y_location + 21,
                              x_location + 15, y_location + 25,
                              x_location + 20, y_location + 25);  // right nozzle
}

/*
 * 30 Days - Lost in Space
 * Day 24 - Back To Orbit
 *
 * Explorer, the day has arrived!  Let's get that lander up into space again.
 * We will initialize our systems by setting our Thruster, Systems and Confirmation
 * switches to "off" and then enable our countdown by turning each of them on in
 * turn.
 *
 * Once everything has been turned on the countdown will begin (so be sure you're
 * all buckled in tight!).  If you see anything abnormal during the countdown you
 * can abort the liftoff by turning off any of the switches.  Simply turn them all
 * off again to re-initialize the sequence.
 *
 * Once the countdown reaches zero the ship will liftoff, placing the lander into
 * a random orbit.  Once the engines fire, the liftoff CANNOT be aborted!
 *
 * Let's get you back into space, Explorer, and next week we'll work to get your
 * fragile lander back to your mother ship!
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - enum
 * - ternary operation
 *
 * Parts and electronics concepts introduced in this lesson.
 * - 
 */

// Explicitly include Arduino.h
#include "Arduino.h"

// Include file for 4 digit - 7 segment display library
#include <TM1637Display.h>

// Extensive documentation for this library can be found at https://github.com/olikraus/u8g2
#include <U8g2lib.h>  // Include file for the U8g2 library.
#include "Wire.h"     // Sometimes required for I2C communications.

// Define macros to convert milliseonds to minutes or seconds, rounded UP to next second.
#define numberOfMinutes(_milliseconds_) (((_milliseconds_ + 999) / 1000) / 60)
#define numberOfSeconds(_milliseconds_) (((_milliseconds_ + 999) / 1000) % 60)

// Pin connections for our 4 digit counter
const byte COUNTER_DISPLAY_DIO_PIN = 4;
const byte COUNTER_DISPLAY_CLK_PIN = 5;
// Construct counter_display handle.
TM1637Display counter_display(COUNTER_DISPLAY_CLK_PIN, COUNTER_DISPLAY_DIO_PIN);

// Define pins for our DIP switches
const byte THRUST_LEVER_PIN = 9;
const byte SYSTEMS_LEVER_PIN = 8;
const byte CONFIRM_LEVER_PIN = 7;

// Define pin for buzzer
const byte BUZZER_PIN = 6;

// Use _2_ version of constructor and firstPage()/nextPage() for OLED
// graphics to save memory.
U8G2_SH1106_128X64_NONAME_2_HW_I2C lander_display(U8G2_R0, /* reset=*/U8X8_PIN_NONE);

// Define size of our lander graphic so it can be accurately placed on display
const byte LANDER_HEIGHT = 25;  // height of our lander image, in bits
const byte LANDER_WIDTH = 20;   // width of our lander image, in bits

// Define 7 Segment display values to spell out "dOnE"
const uint8_t DONE[] = {
  SEG_B | SEG_C | SEG_D | SEG_E | SEG_G,          // d
  SEG_A | SEG_B | SEG_C | SEG_D | SEG_E | SEG_F,  // O
  SEG_C | SEG_E | SEG_G,                          // n
  SEG_A | SEG_D | SEG_E | SEG_F | SEG_G           // E
};

// Define amount of time (in milliseconds) to count down.  To ensure
// that the calculation is done as an unsigned long we append "UL" to
// the values below.  Without this the calculation is done in 16 bit
// arithmetic which causes the value to wrap and be incorrect.
const unsigned long COUNTDOWN_MILLISECONDS = 70UL * 1000UL;

/*
 * The Arduino C++ provides the "enum" command to define multiple, related
 * values where distinguishing between the different values is important, but
 * the actual values aren't.
 *
 * Each name is given it's own value (starting with 0) which can be seen by
 * hovering your mouse over each name below.
 *
 * Enums provide a number of benefits over manually defining a set of constants:
 * 1) An enum groups related constants in a way that clearly defines that they
 *    are variants of a single concept (in this case, the state of our liftoff
 *    sequence).
 * 2) An enum gives an exhaustive list off all valid states and no other values
 *    are valid.
 * 3) An enum creates a new type, and a variable containing an enum value can
 *    ONLY be assigned values defined in the enum.
 */
enum LIFTOFF_STATE {
  INIT,       // Waiting for all switches to be "OFF"
  PENDING,    // Waiting for all switchs to be turned "ON"
  COUNTDOWN,  // Counting down to liftoff
  LIFTOFF,    // Ship is lifting off
  ABORT       // Countdown aborted
};

// *********************************************
void setup() {
  Serial.begin(9600);

  // Configure counter display
  counter_display.setBrightness(7);  // Set maximum brightness (value is 0-7)
  counter_display.clear();           // Clear the display

  // Configure OLED display
  lander_display.begin();                     // Initialize OLED display
  lander_display.setFont(u8g2_font_6x10_tr);  // Set text font
  lander_display.setFontRefHeightText();      // Define how max text height is calculated
  lander_display.setFontPosTop();             // Y coordinate for text is at top of tallest character

  // Configure DIP switch pins
  pinMode(THRUST_LEVER_PIN, INPUT);   // Thrust lever pin
  pinMode(SYSTEMS_LEVER_PIN, INPUT);  // Sysstems lever pin
  pinMode(CONFIRM_LEVER_PIN, INPUT);  // Confirmation lever pin

  lander_display.clearDisplay();  // Clear OLED display
}

// *********************************************
// *              LOOP()                       *
// *********************************************

// To keep beeping and animations steady we will attempt to have each loop
// take the same amount of time.  Occasionally loops may take longer, but
// this constant defines the minimum time each loop will take to run.
const unsigned long MIN_LOOP_TIME = 200;  // minimum 200 ms time per loop

void loop() {
  // Initialize static variables first time through loop().  Any values set
  // during execution will be retained between loop() executions.
  static unsigned long timeRemaining = COUNTDOWN_MILLISECONDS;  // Time remaining before liftoff
  static unsigned long countdown_start_time;                    // millis() value when countdown begins
  static enum LIFTOFF_STATE liftoff_state = INIT;               // Begin sequence in INIT state

  // Here we define a value that is toggled between true/false ever time through the loop
  // This can be used to create a beeping tone or could be used to blink text.
  static bool loop_toggle = true;  // if our loop_toggle is true this time through the loop

  unsigned long loop_start_time = millis();  // save time that this loop begins

  // Read current values of all of our switches as booleans ("on" is true, "off" is false)
  bool thrust_lever = digitalRead(THRUST_LEVER_PIN);
  bool systems_lever = digitalRead(SYSTEMS_LEVER_PIN);
  bool confirm_lever = digitalRead(CONFIRM_LEVER_PIN);

  // Update OLED display with the current status of our liftoff sequence.
  updateLanderDisplay(liftoff_state, thrust_lever, systems_lever, confirm_lever);

  /*
   * This is the primary decision part of our loop.  It makes decisions based on the
   * current state of our liftoff sequence, switching states as different events are
   * detected.
   *
   * NOTE: Normally this section of code would done in a switch/case construct.  However
   *       a bug in the compiler caused certain cases to NEVER execute.  Because of this
   *       bug (hopefully fixed soon) we use the less clear if/else if/else format.
   *
   * A switch/case version would look like:
   * switch(liftoff_state) {
   *   case INIT:
   *     // code for INIT state
   *     break;
   *   [...]
   *   case ABORT:
   *     // code for ABORT state
   *     break;
   * }
   */

  if (liftoff_state == INIT) {  // INIT state
    // INIT state requires that all switches start out as "off".

    // If all three switches are OFF (false) we can turn off the beeping
    // and change state to PENDING.
    if (!thrust_lever && !systems_lever && !confirm_lever) {
      noTone(BUZZER_PIN);
      liftoff_state = PENDING;
    } else {  // not all switches are "off"
      // Play low, "beeping" tone to indicate switches aren't all "off"
      if (loop_toggle) {        // if our loop_toggle is true this time through the loop
        tone(BUZZER_PIN, 100);  // play short tone entire loop
      } else {
        noTone(BUZZER_PIN);  // turn off tone this time through the loop
      }
    }
    // end of INIT state
  } else if (liftoff_state == PENDING) {
    // Now wait for all switches to be turned ON to initiate countdown.
    if (thrust_lever && systems_lever && confirm_lever) {
      // blink the countdown on our timer before beginning the countdown
      for (int i = 0; i < 3; i++) {
        counter_display.clear();
        delay(MIN_LOOP_TIME);
        displayCounter(COUNTDOWN_MILLISECONDS);
        delay(MIN_LOOP_TIME);
      }
      countdown_start_time = millis();  // Save current millis() when countdown begins
      liftoff_state = COUNTDOWN;
    }
    // end of PENDING state
  } else if (liftoff_state == COUNTDOWN) {
    // Update our remaining time by subtracting the countdown start time from current
    // execution time (in milliseconds).  If this value is greater than our countdown
    // time then our countdown is complete and we set time remaining to 0 to prevent
    // the time remaining from going negative.
    unsigned long elapsed_time = millis() - countdown_start_time;
    if (elapsed_time > COUNTDOWN_MILLISECONDS) {  // Countdown complete!
      timeRemaining = 0;                          // No time remaining
      liftoff_state = LIFTOFF;                    // initiate liftoff state
    } else {
      timeRemaining = COUNTDOWN_MILLISECONDS - elapsed_time;  // decrease time remaining
    }

    // if any switch is turned off during countdown then we abort takeoff.
    if (!thrust_lever || !systems_lever || !confirm_lever) {
      liftoff_state = ABORT;
    }
    displayCounter(timeRemaining);  // Display countdown time in minutes:seconds on counter display
    // end of COUNTDOWN state
  } else if (liftoff_state == LIFTOFF) {  // Liftoff!
    counter_display.setSegments(DONE);    // Display "dOnE" on our counter

    // Play TADA! tones followed by sound of our thrusters firing
    tone(BUZZER_PIN, 300);
    delay(200);
    tone(BUZZER_PIN, 500);
    delay(400);
    tone(BUZZER_PIN, 38, 5000);  // Play engines for first 5 seconds

    // Animate final display forever.  This while loop runs until HERO is reset or
    // new code is uploaded.  During liftoff the ship graphic moves up the right
    // side of the display, so we need to update the OLED display repeately.
    while (true) {
      updateLanderDisplay(liftoff_state, true, true, true);
    }
    // THIS LINE IS NEVER REACHED
    // end of LIFTOFF state
  } else if (liftoff_state == ABORT) {
    // If countdown was aborted we play an alert tone and delay before
    // moving state back to our original INIT state.
    tone(BUZZER_PIN, 100, 1000);
    delay(5000);           // show display for 5 seconds
    liftoff_state = INIT;  // set state back to INIT (waiting switches to be all OFF)
  }

  // If loop has taken LESS than our minimum loop time then delay the remaining
  // time to keep loops at least that long.
  unsigned long loop_time = millis() - loop_start_time;
  if (loop_time < MIN_LOOP_TIME) {
    delay(MIN_LOOP_TIME - loop_time);  // delay remaining time
  }

  // Toggle our loop toggle between true/false each time through main loop.
  loop_toggle = !loop_toggle;
}

// *********************************************
// *          Update OLED display              *
// *********************************************
const byte MAX_LANDER_SPEED = 5;

void updateLanderDisplay(enum LIFTOFF_STATE liftoff_state,
                         bool thruster_lever,
                         bool systems_lever,
                         bool confirm_lever) {
  static int lander_height = lander_display.getDisplayHeight() - LANDER_HEIGHT;
  static byte current_lander_speed = 1;

  // Use the firstPage()/nextPage() commands to update our display using smaller
  // data buffer.  Only a portion of the display is updated each time through
  // this loop.  The SAME display should be drawn each time through this "do" loop.
  lander_display.firstPage();
  do {
    lander_display.setFontPosTop();
    byte y_offset = drawString(0, 0, "Exploration Lander");
    y_offset = drawString(0, y_offset, "Liftoff Sequence");

    if (liftoff_state == LIFTOFF) {
      const char LIFTOFF_TEXT[] = "Liftoff!";
      // Display liftoff in center of available space
      byte y_center = y_offset + ((lander_display.getDisplayHeight() - y_offset) / 2);
      // Serial.println(y_center);
      lander_display.setFontPosCenter();  // display text vertically centered
      static byte text_width = lander_display.getStrWidth(LIFTOFF_TEXT);
      static byte x_left = ((lander_display.getDisplayWidth() - LANDER_WIDTH) / 2) - (text_width / 2);
      lander_display.drawStr(x_left, y_center, LIFTOFF_TEXT);
    } else if (liftoff_state == ABORT) {
      const char ABORT_TEXT[] = "ABORTED!";
      // Display liftoff in center of available space
      byte y_center = y_offset + ((lander_display.getDisplayHeight() - y_offset) / 2);
      lander_display.setFontPosCenter();  // display text vertically centered
      static byte text_width = lander_display.getStrWidth(ABORT_TEXT);
      static byte x_left = ((lander_display.getDisplayWidth() - LANDER_WIDTH) / 2) - (text_width / 2);
      lander_display.drawStr(x_left, y_center, ABORT_TEXT);
    } else {
      // Set y_offset to point four lines above bottom of display
      y_offset = lander_display.getDisplayHeight() - (4 * lander_display.getMaxCharHeight());
      // Display last four lines
      y_offset = drawString(0, y_offset,
                            (String("Thrusters: ") + String(thruster_lever ? "ON" : "OFF")).c_str());
      y_offset = drawString(0, y_offset,
                            (String("Systems  : ") + String(systems_lever ? "ON" : "OFF")).c_str());
      y_offset = drawString(0, y_offset,
                            (String("Confirm  : ") + String(confirm_lever ? "ON" : "OFF")).c_str());

      // Set y_offset to display text at bottom of display.
      y_offset = lander_display.getDisplayHeight() - lander_display.getMaxCharHeight();
      drawString(0, y_offset, (String("Countdown ") + liftoffStateToString(liftoff_state)).c_str());
    }
    // Draw a picture of our lander on right side of display.  During the liftoff this
    // will be animated by changing the lander_height variable OUTSIDE the "do" loop.
    displayLander(lander_display.getDisplayWidth() - LANDER_WIDTH,
                  lander_height);
  } while (lander_display.nextPage());

  // Set height of lander image on screen to animate liftoff image, increasing speed
  // to MAX during liftoff.  This value is only changed OUTSIDE the firstPage()/nextPage()
  // loop and sets the new height for the lander to be drawn the NEXT time the OLED
  // display is updated.
  if (liftoff_state == LIFTOFF) {
    // Move our lander graphic up on the display based on our current speed
    lander_height -= current_lander_speed;
    // If the graphic has moved entirely off the top of the display we reset
    // the height to make it re-appear at the bottom.
    if (lander_height < -LANDER_HEIGHT) {
      lander_height = lander_display.getDisplayHeight();  // start again at bottom of screen
    }
    // To accellerate, increase the movement speed until we reach our maximum speed
    if (current_lander_speed < MAX_LANDER_SPEED) {
      current_lander_speed += 1;
    }
  }
}

// "helper" function that returns a different string for each enum state.
String liftoffStateToString(enum LIFTOFF_STATE liftoff_state) {
  switch (liftoff_state) {
    case INIT:
      return ("Init");
      break;
    case PENDING:
      return ("Pending");
      break;
    case COUNTDOWN:
      return ("Active");
      break;
    case LIFTOFF:
      return ("Complete");
      break;
    case ABORT:
      return ("ABORT");
      break;
  }
}

// Display milliseconds on our counter as minutes:seconds (MM:SS)
void displayCounter(unsigned long milliseconds) {
  // To display the countdown in mm:ss format, separate the parts
  byte minutes = numberOfMinutes(milliseconds);
  byte seconds = numberOfSeconds(milliseconds);

  // Display the minutes in the first two places, with colon
  counter_display.showNumberDecEx(minutes, 0b01000000, true, 2, 0);
  // This displays the seconds in the last two places
  counter_display.showNumberDecEx(seconds, 0, true, 2, 2);
}

// Draw a line of text on our OLED display at x, y, returning new y
// value that is immediately below the new line of text.
byte drawString(byte x, byte y, char *string) {
  lander_display.drawStr(x, y, string);
  return (y + lander_display.getMaxCharHeight());  // return new y_offset on display
}

// Draw an image of our lander drawn with frames and triangles
// at location x_location, y_location (relative to the upper left corner).
void displayLander(byte x_location, int y_location) {
  lander_display.drawFrame(x_location + 7, y_location, 6, 5);        // ship top
  lander_display.drawFrame(x_location + 5, y_location + 4, 10, 20);  // ship center
  lander_display.drawFrame(x_location, y_location + 6, 6, 16);       // left pod
  lander_display.drawFrame(x_location + 14, y_location + 6, 6, 16);  // right pod
  lander_display.drawTriangle(x_location + 2, y_location + 21,
                              x_location, y_location + 25,
                              x_location + 4, y_location + 25);  // left nozzle
  lander_display.drawTriangle(x_location + 18, y_location + 21,
                              x_location + 15, y_location + 25,
                              x_location + 20, y_location + 25);  // right nozzle
}

/*
 * 30 Days - Lost in Space
 * Day 27 - Fun With Bitmaps, Part 2
 *
 * OK, now we know how to display bitmaps that cover the entire display,
 * but it would be very inefficient to pre-draw every possible display.
 *
 * Instead, we can reduce the size of our bitmaps to whatever size is
 * desired and then display the partial bitmaps.
 *
 * In addition, we won't just be displaying all the bitmaps in a loop so
 * we need a way to *select* which bitmaps are being displayed.
 *
 * Let's use our DIP switches to display one of eight different bitmaps.
 * Since we only have three switches we'll read each as a bit in a binary
 * number.  This way three switches can give us eight distinct values.
 *
 * We'll also add our 4 digit 7 segment display to show which picture
 * is currently being displayed.
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - partial bitmaps
 * - switches to binary
 * - creating include files
 *
 * Parts and electronics concepts introduced in this lesson.
 * - 
 */

// Explicitly include Arduino.h
#include "Arduino.h"

// Extensive documentation for this library can be found at https://github.com/olikraus/u8g2
#include <U8g2lib.h>  // Include file for the U8g2 library.
#include "Wire.h"     // Sometimes required for I2C communications.

// Use _2_ version of constructor and firstPage()/nextPage() for OLED
// graphics to save memory.
U8G2_SH1106_128X64_NONAME_2_HW_I2C lander_display(U8G2_R0, /* reset=*/U8X8_PIN_NONE);

/*
 * Yesterday we showed a way to move our large bitmap declarations so that
 * our setup() and loop() code was near the top of our sketch using "forward
 * declarations".
 *
 * However, it turns out there's a simpler way, and we've seen it used many
 * times in the past.  We can simply MOVE our declarations into one or more
 * include files and then include them at the top of our sketch before we
 * reference them.
 *
 * To create a new file, simply click the "..." to the right of the tab bar with
 * our sketch name and select "New Tab".  Enter the name for the new file and
 * click the tab to edit.  This lets us move all of our bitmaps into a separate
 * file so we don't have to scroll through them.
 */
#include "switch_bitmaps.h"

// Create an array of pointers to each of the bitmap images.
const static char* SWITCH_BITMAPS[] = {
  SWITCHES_ZERO,
  SWITCHES_ONE,
  SWITCHES_TWO,
  SWITCHES_THREE,
  SWITCHES_FOUR,
  SWITCHES_FIVE,
  SWITCHES_SIX,
  SWITCHES_SEVEN,
};

// Include file for 4 digit - 7 segment display library
#include <TM1637Display.h>
const byte BITMAP_NUMBER_DISPLAY_DIO_PIN = 2;
const byte BITMAP_NUMBER_DISPLAY_CLK_PIN = 3;
// Construct bitmap_number_display handle.
TM1637Display bitmap_number_display(BITMAP_NUMBER_DISPLAY_CLK_PIN, BITMAP_NUMBER_DISPLAY_DIO_PIN);

// Define pins for our DIP switches
// We will need almost all pins for Day 29, so here we show that we can use ANALOG
// pins as digitial pins when necessary.
const byte SWITCH_BIT_0_PIN = A2;  // switch for bit 0 of our 3 bit value
const byte SWITCH_BIT_1_PIN = A1;  // switch for bit 1 of our 3 bit value
const byte SWITCH_BIT_2_PIN = A0;  // switch for bit 2 of our 3 bit value

// ************************************************
void setup(void) {
  Serial.begin(9600);

  // Configure counter display
  bitmap_number_display.setBrightness(7);  // Set maximum brightness (value is 0-7)
  bitmap_number_display.clear();           // Clear the display

  // Configure DIP switch pins
  pinMode(SWITCH_BIT_0_PIN, INPUT);  // switch for bit 0 of our 3 bit value
  pinMode(SWITCH_BIT_1_PIN, INPUT);  // switch for bit 1 of our 3 bit value
  pinMode(SWITCH_BIT_2_PIN, INPUT);  // switch for bit 2 of our 3 bit value

  lander_display.begin();  // initialize lander display
}

// ************************************************
void loop(void) {
  // Calculate our x and y offsets for our bitmap graphics
  byte x_offset = (lander_display.getDisplayWidth() - BITMAP_WIDTH) / 2;
  byte y_offset = (lander_display.getDisplayHeight() - BITMAP_HEIGHT) / 2;

  /*
   * Now we build up a 3 bit binary number by reading each of our switches,
   * ensuring that the read value is 1 for on and 0 for off (using the
   * ternary notation), and then shifting each bit to it's desired location.
   * This converts our three switches to the values 0-7:
   *   0b00000000 = 0
   *   0b00000001 = 1
   *   0b00000010 = 2
   *   0b00000011 = 3
   *   0b00000100 = 4
   *   0b00000101 = 5
   *   0b00000110 = 6
   *   0b00000011 = 7
   */

  // Read bit 0 (0b00000001), ensure 0 or 1 and save.
  byte switch_value = digitalRead(SWITCH_BIT_0_PIN) == HIGH ? 1 : 0;
  // Read bit 1 (0b00000010), ensure 0 or 1, shift left 1 bit and OR it into current value.
  switch_value |= (digitalRead(SWITCH_BIT_1_PIN) == HIGH ? 1 : 0) << 1;
  // Read bit 2 (0b00000100), ensure 0 or 1, shift left 2 bits and OR it into current value.
  switch_value |= (digitalRead(SWITCH_BIT_2_PIN) == HIGH ? 1 : 0) << 2;

  // Display calculated switch value on our 4 digit display
  bitmap_number_display.showNumberDecEx(switch_value);

  // Display selected bitmap on our OLED lander display
  lander_display.firstPage();
  do {
    // .drawXBMP() displays each bitmap centered in the display based
    // on it's size.
    lander_display.drawXBMP(x_offset, y_offset, BITMAP_WIDTH, BITMAP_HEIGHT, SWITCH_BITMAPS[switch_value]);
  } while (lander_display.nextPage());

  delay(100);
}

/*
 * 30 Days - Lost in Space
 * Day 28 - Landing Gear
 *
 * Now that the safety of the mother ship is in sight we need to consider
 * our final landing.  While the lander has landing gear, it (of course) was
 * controlled from the failed computer.
 *
 * We'll start by confirming all switches are in the OFF position and then
 * enable our approach code.  Currently the approach code will only excersize
 * the landing gear, but we'll build on that later to perform our approach
 * and landing at the mother ship.
 *
 * We'll add your 16 button matrix to our control panel and use two
 * of the buttons to raise and lower the landing gear.  You'll need
 * confirmation of the gear position, so we'll use the OLED to display
 * our gear status using bitmaps.
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - partial bitmaps
 * - using analog pins as digital pins
 * - switches to binary
 * - creating include files
 * - enum with defined values
 *
 * Parts and electronics concepts introduced in this lesson.
 * - 
 */

// Explicitly include Arduino.h
#include "Arduino.h"

// Extensive documentation for this library can be found at https://github.com/olikraus/u8g2
#include <U8g2lib.h>  // Include file for the U8g2 library.
#include "Wire.h"     // Sometimes required for I2C communications.

// Use _2_ version of constructor and firstPage()/nextPage() for OLED
// graphics to save memory.
U8G2_SH1106_128X64_NONAME_2_HW_I2C lander_display(U8G2_R0, /* reset=*/U8X8_PIN_NONE);

/*
 * Yesterday we showed a way to move our large bitmap declarations so that
 * our setup() and loop() code was near the top of our sketch using "forward
 * declarations".
 *
 * However, it turns out there's a simpler way, and we've seen it used many
 * times in the past.  We can simply MOVE our declarations into one or more
 * include files and then include them at the top of our sketch before we
 * reference them.
 *
 * To create a new file, simply click the "..." to the right of the tab bar with
 * our sketch name and select "New Tab".  Enter the name for the new file and
 * click the tab to edit.  This lets us move all of our bitmaps into a separate
 * file so we don't have to scroll through them.
 */
// ************************************************
#include "landing_gear_bitmaps.h"

// Create an array of pointers to each of the bitmap images.
const static char* SWITCH_BITMAPS[] = {
  LANDING_1,
  LANDING_2,
  LANDING_3,
  LANDING_4,
};

// ************************************************
// Include file for 4 digit - 7 segment display library
#include <TM1637Display.h>
const byte BITMAP_NUMBER_DISPLAY_DIO_PIN = 2;
const byte BITMAP_NUMBER_DISPLAY_CLK_PIN = 3;
// Construct bitmap_number_display handle.
TM1637Display bitmap_number_display(BITMAP_NUMBER_DISPLAY_CLK_PIN, BITMAP_NUMBER_DISPLAY_DIO_PIN);

// ************************************************
// Define pins for our DIP switches
// We will need almost all pins for Day 29, so here we show that we can use ANALOG
// pins as digitial pins when necessary.
const byte CONFIRM_LEVER_PIN = A2;  // switch for bit 0 of our 3 bit value
const byte SYSTEMS_LEVER_PIN = A1;  // switch for bit 1 of our 3 bit value
const byte THRUST_LEVER_PIN = A0;   // switch for bit 2 of our 3 bit value

// ************************************************
// Setup for our 4x4 button matrix.
#include <Keypad.h>  // 4x4 button matrix keypad library
const byte ROWS = 4;
const byte COLS = 4;

byte colPins[ROWS] = { 10, 11, 12, 13 };
byte rowPins[COLS] = { 9, 8, 7, 6 };

char buttons[ROWS][COLS] = {
  { '1', '2', '3', 'A' },  // 1st row
  { '4', '5', '6', 'B' },  // 2nd row
  { '7', '8', '9', 'C' },  // 3rd row
  { '*', '0', '#', 'D' }   // 4th row
};

Keypad myAwesomePad = Keypad(makeKeymap(buttons), rowPins, colPins, ROWS, COLS);

// ************************************************
// Here are the states our code will run through.  We'll build on this later to
// perform the actual approach flight and landing in the mother ship bay.
enum APPROACH_STATE {
  APPROACH_INIT,       // Ensure all switches are off to begin
  APPROACH_PREFLIGHT,  //
  // APPROACH_IN_FLIGHT,
  APPROACH_FINAL,  // Lower landing gear!
  // APPROACH_TOO_FAST,
  // APPROACH_DOCKED
};

const int GEAR_BITMAP_COUNT = sizeof(SWITCH_BITMAPS) / sizeof(SWITCH_BITMAPS[0]);
enum GEAR_STATE {
  GEAR_IDLE = 0,
  GEAR_LOWERING = 1,
  GEAR_RAISING = -1
};

// ************************************************
void setup(void) {
  Serial.begin(9600);

  // Configure counter display
  bitmap_number_display.setBrightness(7);  // Set maximum brightness (value is 0-7)
  bitmap_number_display.clear();           // Clear the display

  // Configure DIP switch pins
  pinMode(CONFIRM_LEVER_PIN, INPUT);  // switch for bit 0 of our 3 bit value
  pinMode(SYSTEMS_LEVER_PIN, INPUT);  // switch for bit 1 of our 3 bit value
  pinMode(THRUST_LEVER_PIN, INPUT);   // switch for bit 2 of our 3 bit value

  lander_display.begin();                     // initialize lander display
  lander_display.setFont(u8g2_font_6x10_tr);  // Set text font
  lander_display.setFontRefHeightText();      // Define how max text height is calculated
  lander_display.setFontPosTop();             // Y coordinate for text is at top of tallest character
}

// ************************************************
void loop(void) {
  static int current_gear_bitmap = 0;  // Start with image of lander with gear up
  static enum APPROACH_STATE approach_state = APPROACH_INIT;
  // APPROACH_FINAL; //
  static enum GEAR_STATE gear_state = GEAR_IDLE;
  static char last_key = -1;  // key previously seen

  // Read current values of all of our switches as booleans ("on" is true, "off" is false)
  bool thrust_lever = digitalRead(THRUST_LEVER_PIN);
  bool systems_lever = digitalRead(SYSTEMS_LEVER_PIN);
  bool confirm_lever = digitalRead(CONFIRM_LEVER_PIN);
  // Serial.println(approach_state);
  // Serial.print("  Switches: ");
  // Serial.print(thrust_lever);
  // Serial.print(", ");
  // Serial.print(systems_lever);
  // Serial.print(", ");
  // Serial.println(confirm_lever);

  switch (approach_state) {
    case APPROACH_INIT:
      // Serial.println("case APPROACH_INIT");
      if (!thrust_lever && !systems_lever && !confirm_lever) {
        approach_state = APPROACH_PREFLIGHT;
      }
      break;
    case APPROACH_PREFLIGHT:
      // Serial.println("case APPROACH_PREFLIGHT");
      if (thrust_lever && systems_lever && confirm_lever) {
        approach_state = APPROACH_FINAL;
      }
      break;
    // case APPROACH_IN_FLIGHT:
    //   Serial.println("case APPROACH_IN_FLIGHT");
    //   approach_state = APPROACH_FINAL;
    //   break;
    case APPROACH_FINAL:
      // Serial.println("case APPROACH_FINAL");
      char customKey = myAwesomePad.getKey();
      if (customKey && customKey != last_key) {
        Serial.println(customKey);
        last_key = customKey;
      }

      switch (customKey) {
        case 'A':  // Lower landing gear unless already lowered
          if (current_gear_bitmap != GEAR_BITMAP_COUNT - 1) {
            gear_state = GEAR_LOWERING;
          }
          break;
        case 'B':  // Raise landing gear unless already raised
          if (current_gear_bitmap != 0) {
            gear_state = GEAR_RAISING;
          }
      }
      break;
  }
  // if (gear_state != GEAR_IDLE) {
  current_gear_bitmap += gear_state;
  if (current_gear_bitmap == 0 || current_gear_bitmap == GEAR_BITMAP_COUNT - 1) {
    gear_state = GEAR_IDLE;
  }

  Serial.print("Gear: ");
  Serial.println(current_gear_bitmap);
  // Display calculated switch value on our 4 digit display
  // bitmap_number_display.showNumberDecEx(switch_value);

  // Display selected bitmap on our OLED lander display
  lander_display.firstPage();
  do {
    switch (approach_state) {
      case APPROACH_INIT:
      case APPROACH_PREFLIGHT:
        preflightDisplay(approach_state, thrust_lever, systems_lever, confirm_lever);
        break;
      case APPROACH_FINAL:
        finalDisplay(current_gear_bitmap);
        break;
    }

  } while (lander_display.nextPage());

  delay(100);
}

void preflightDisplay(enum APPROACH_STATE approach_state,
                      bool thruster_lever,
                      bool systems_lever,
                      bool confirm_lever) {
  lander_display.setFontPosTop();
  byte y_offset = drawString(0, 0, "Exploration Lander");
  y_offset = drawString(0, y_offset, "Approach Sequence");
  // Set y_offset to point four lines above bottom of display
  y_offset = lander_display.getDisplayHeight() - (4 * lander_display.getMaxCharHeight());
  // Display last four lines
  y_offset = drawString(0, y_offset,
                        (String("Thrusters: ") + String(thruster_lever ? "ON" : "OFF")).c_str());
  y_offset = drawString(0, y_offset,
                        (String("Systems  : ") + String(systems_lever ? "ON" : "OFF")).c_str());
  y_offset = drawString(0, y_offset,
                        (String("Confirm  : ") + String(confirm_lever ? "ON" : "OFF")).c_str());

  // Set y_offset to display text at bottom of display.
  y_offset = lander_display.getDisplayHeight() - lander_display.getMaxCharHeight();
  drawString(0, y_offset, (String("Countdown ") + liftoffStateToString(approach_state)).c_str());
}

void finalDisplay(int current_gear_bitmap) {
  // Flash lander bitmap if gear isn't down
  // display current gear bitmap as gear lowers

  // .drawXBMP() displays each bitmap centered in the display based
  // on it's size.

  // Calculate our x and y offsets for our bitmap graphics
  byte x_offset = (lander_display.getDisplayWidth() - LANDING_GEAR_BITMAP_WIDTH) / 2;
  byte y_offset = (lander_display.getDisplayHeight() - LANDING_GEAR_BITMAP_HEIGHT) / 2;

  lander_display.drawXBMP(x_offset, y_offset,
                          LANDING_GEAR_BITMAP_WIDTH, LANDING_GEAR_BITMAP_HEIGHT,
                          SWITCH_BITMAPS[current_gear_bitmap]);
}

// "helper" function that returns a different string for each enum state.
String liftoffStateToString(enum APPROACH_STATE approach_state) {
  switch (approach_state) {
    case APPROACH_INIT:
      return ("Init");
      break;
    case APPROACH_PREFLIGHT:
      return ("Preflight");
      break;
      // case COUNTDOWN:
      //   return ("Active");
      //   break;
      // case LIFTOFF:
      //   return ("Complete");
      //   break;
      // case ABORT:
      //   return ("ABORT");
      //   break;
  }
}

// Draw a line of text on our OLED display at x, y, returning new y
// value that is immediately below the new line of text.
byte drawString(byte x, byte y, char* string) {
  lander_display.drawStr(x, y, string);
  return (y + lander_display.getMaxCharHeight());  // return new y_offset on display
}

/*
 * 30 Days - Lost in Space
 * Day 29 - Landing Gear
 *
 * Congratulations, Explorer!  Today is the day you (hopefully) rejoin
 * the mother ship.  Now, space is BIG, and your docking bay is a small
 * target.
 *
 * Today we will add our thrusters and steering into your controls so that
 * you can initiate your final burn to the mother ship and control the
 * approach to successfully enter the docking bay for a successful landing.
 *
 * You will first need to ensure that our control panel is in a known state
 * by turning off all of the control switches.  Once that is complete you
 * will enable each system in turn by switching all three switches on.
 *
 * Then the display will change to our Approach/Landing display.  The current
 * speed of the lander is displayed in the upper right corner.  On the left
 * side of the display is our target radar.  The distance to the mother ship
 * is shown on our 4 digiti display.
 *
 * In the center of the radar display there is a center point indicating
 * what direction our lander is pointed.  You may also see another point
 * which is the radar return for the mother ship.  Instabilities in our
 * (damaged) lander may cause that target to move, and your job will be
 * to steer the lander during approach to ensure a safe landing.
 *
 * We will use our button matrix to control our steering thrusters, using
 * 8 of our buttons.  In addition, we will use 2 of the buttons for Gear Down
 * and Gear Up and two more for Thrust Up and Thrust Down.
 * 
 * We'll lable the buttons with U for Up, D for Down, L for Left and R for Right.
 * UL means move Up and Left.  The gear buttons are GD and GU (Gear Down and
 * Gear Up) and Thrust controls are labeled T+ and T- for Thrust Up and Thrust
 * Down.
 *
 * UL |  U | UR | GD
 * -----------------
 *  L |    |  R | GU
 * -----------------
 * DL |  D | DR | T+
 * -----------------
 *    |    |    | T-
 *
 * Once you see the radar display you can begin to add thrust using the T+
 * button.  As the speed of our lander increases you will see the distance
 * to our mother ship decrease.
 *
 * If the mother ship drifts off-center you will see arrows appear on the
 * outside of the display to indicate which steering thruster to fire.  Just
 * press the appropriate button until the arrows disappear to keep the
 * mother ship centered.
 *
 * Remember to give yourself enough time to REDUCE your speed as you approach
 * the mother ship.  You must land with a speed of 2 or less for a safe landing!
 *
 * As you near the mother ship you will get a reminder to lower your landing
 * gear.  Use the Gear Down button (upper right) to lower the gear.
 *
 * Keep the mother ship centered, speed low enough and land with your gear down
 * to be safely re-united with the mother ship.
 * 
 * NOTE:
 * The original plan was for us to add our rotary encoder to our design to
 * control the thrusters, but as sometimes happens when working with complex
 * devices our plans needed to change.  It turns out that there is some type
 * of conflict that prevents our rotary encoder from working correctly when
 * it's added to the switches, OLED display and 4-digit counter.
 *
 * However, we have unused buttons on the button matrix so we will use
 * those to control our thrust.
 *
 * Learn more at https://learn.inventr.io/adventure
 *
 * Alex Eschenauer
 * David Schmidt
 * Greg Lyzenga
 */

/*
 * Arduino concepts introduced/documented in this lesson.
 * - Random numbers (randomSeed() and random())
 * - sprintf()
 *
 * Parts and electronics concepts introduced in this lesson.
 * - 
 */

// Explicitly include Arduino.h
#include "Arduino.h"

// ************************************************
//    Setup for OLED display and graphics library
// Include files for Graphics library used for our OLED display.
// Extensive documentation for this library can be found at https://github.com/olikraus/u8g2
#include <U8g2lib.h>  // Include file for the U8g2 library.
#include "Wire.h"     // Sometimes required for I2C communications.

// Use _2_ version of constructor and firstPage()/nextPage() for OLED
// graphics to save memory.
U8G2_SH1106_128X64_NONAME_2_HW_I2C lander_display(U8G2_R0, /* reset=*/U8X8_PIN_NONE);

/*
 * Again we'll use separate files to store our bitmap images.
 *
 * To create a new file, simply click the "..." to the right of the tab bar with
 * our sketch name and select "New Tab".  Enter the name for the new file and
 * click the tab to edit.  This lets us move all of our bitmaps into a separate
 * file so we don't have to scroll through them.
 */
#include "radar_arrows.h"
#include "small_landing_gear_bitmaps.h"
#include "ending_bitmaps.h"

// Create an array of pointers to each of the bitmap images.
// For a smoother animation you could simply add additional bitmaps
// into the sequence below and the code will automatically adjust.
const static char* LANDER_BITMAPS[] = {
  LANDING_GEAR_1,  // Gear up
  LANDING_GEAR_2,  // Gear lowering
  LANDING_GEAR_3,  // Gear lowering
  LANDING_GEAR_4,  // Gear down
};

// Calculate how many gear bitmaps we have by dividing the total size of the
// array by the size of a single item in the array.
const int GEAR_BITMAP_COUNT = sizeof(LANDER_BITMAPS) / sizeof(LANDER_BITMAPS[0]);

// Gear states with defined values used to change bitmap index.
enum GEAR_STATE {
  GEAR_IDLE = 0,      // Landing gear idle.  Don't change index when added to current
  GEAR_LOWERING = 1,  // Lowering gear, adds one to index for next "lowoer" bitmap
  GEAR_RAISING = -1   // Raising gear, subtracts one from index, showing gear retracting
};

// ************************************************
//   Setup for 4-digit, 7-segment speed display
#include <TM1637Display.h>
const byte DISTANCE_DISPLAY_DIO_PIN = 4;
const byte DISTANCE_DISPLAY_CLK_PIN = 5;
// Construct distance display handle.
TM1637Display distance_display(DISTANCE_DISPLAY_CLK_PIN, DISTANCE_DISPLAY_DIO_PIN);

// ************************************************
//   Setup for DIP switch pins.
//
// We will need almost all pins for Day 29, so here we show that we can use ANALOG
// pins as digitial pins when digital pins are scarce.
const byte CONFIRM_LEVER_PIN = A2;  // switch for bit 0 of our 3 bit value
const byte SYSTEMS_LEVER_PIN = A1;  // switch for bit 1 of our 3 bit value
const byte THRUST_LEVER_PIN = A0;   // switch for bit 2 of our 3 bit value

// ************************************************
//   Setup for our 4x4 button matrix.
#include <Keypad.h>  // 4x4 button matrix keypad library
const byte CONTROL_ROW_COUNT = 4;
const byte CONTROL_COLUMN_COUNT = 4;

const byte COLUMN_PINS[CONTROL_COLUMN_COUNT] = { 10, 11, 12, 13 };
const byte ROW_PINS[CONTROL_ROW_COUNT] = { 9, 8, 7, 6 };

// The Keypad library isn't restricted to just returning numbers or letters.
// Since we will be using the button matrix to control our lander we define
// an enum with our commands and then set up the buttons to return those
// values.
enum LANDER_CONTROLS {
  UNUSED,
  STEER_UP,
  STEER_DOWN,
  STEER_LEFT,
  STEER_RIGHT,
  STEER_UP_RIGHT,
  STEER_UP_LEFT,
  STEER_DOWN_RIGHT,
  STEER_DOWN_LEFT,
  LOWER_GEAR,
  RAISE_GEAR,
  RAISE_SPEED,
  LOWER_SPEED,
};

// Define our button array using constants to be returned for each button
char control_buttons[CONTROL_ROW_COUNT][CONTROL_COLUMN_COUNT] = {
  { STEER_UP_LEFT, STEER_UP, STEER_UP_RIGHT, LOWER_GEAR },         // 1st row
  { STEER_LEFT, UNUSED, STEER_RIGHT, RAISE_GEAR },                 // 2nd row
  { STEER_DOWN_LEFT, STEER_DOWN, STEER_DOWN_RIGHT, RAISE_SPEED },  // 3rd row
  { UNUSED, UNUSED, UNUSED, LOWER_SPEED },                         // 4th row
};

// Create lander button control object.
Keypad lander_controls = Keypad(makeKeymap(control_buttons), ROW_PINS, COLUMN_PINS,
                                CONTROL_ROW_COUNT, CONTROL_COLUMN_COUNT);

// ************************************************
// Here are the states our code will run through to perform the actual
// approach flight and landing in the mother ship bay.
enum APPROACH_STATE {
  APPROACH_INIT,       // Ensure all switches are off to begin
  APPROACH_PREFLIGHT,  // Wait for all switches to be enabled
  APPROACH_IN_FLIGHT,  // Begin to approach mother ship
  APPROACH_FINAL       // Lower landing gear!
};

// Use this value for our starting distance (just made up)
const int INITIAL_DISTANCE = 1394;  // how far to mother ship

// Maximum size of mother ship docking bay.  Initial display of
// mother ship is small dot, but expands to this size as we approach
//
// Odd nmumbers used to make it easy to center (same size to either
// size of center point).
const byte MAX_MOTHER_SHIP_WIDTH = 21;
const byte MAX_MOTHER_SHIP_HEIGHT = 15;

// ************************************************
//                     SETUP()
// ************************************************
void setup(void) {
  Serial.begin(9600);  // Initialize Serial console in case you want debut messages

  // We use random numbers to move the target mother ship randomly.
  // In order to get different random numbers each time we use this
  // function which reads from our UNCONNECTED analog pin which is
  // floating and thus will return different numbers.
  randomSeed(analogRead(A3));

  // Configure OLED display
  lander_display.begin();                     // initialize lander display
  lander_display.setFont(u8g2_font_6x10_tr);  // Set text font
  lander_display.setFontRefHeightText();      // Define how max text height is calculated
  lander_display.setFontPosTop();             // Y coordinate for text is at top of tallest character

  // Configure counter display
  distance_display.setBrightness(7);  // Set maximum brightness (value is 0-7)
  distance_display.clear();           // Clear the display

  // Configure DIP switch pins
  pinMode(CONFIRM_LEVER_PIN, INPUT);  // switch for bit 0 of our 3 bit value
  pinMode(SYSTEMS_LEVER_PIN, INPUT);  // switch for bit 1 of our 3 bit value
  pinMode(THRUST_LEVER_PIN, INPUT);   // switch for bit 2 of our 3 bit value
}

// ************************************************
//                     LOOP()
// ************************************************
void loop(void) {
  // Static variables that will retain state between loop() executions
  static unsigned long approach_start_time = 0;               // time thrusters are first fired
  static int current_gear_bitmap_index = 0;                   // Image of lander with gear up
  static enum APPROACH_STATE approach_state = APPROACH_INIT;  // Initial approach state
  static enum GEAR_STATE gear_state = GEAR_IDLE;              // Inital landing gear state
  static int lander_distance = INITIAL_DISTANCE;
  static int lander_speed = 0;  // Initial lander speed relative to mother ship
  // These will track the "drift" of the mother ship from center of radar
  static int mother_ship_x_offset = 0;
  static int mother_ship_y_offset = 0;

  // Read current values of all of our switches as booleans ("on" is true, "off" is false)
  bool thrust_lever = digitalRead(THRUST_LEVER_PIN);
  bool systems_lever = digitalRead(SYSTEMS_LEVER_PIN);
  bool confirm_lever = digitalRead(CONFIRM_LEVER_PIN);

  /*
   * Primary control state machine.
   *
   * Based on the current state of our approach to the lander, handle each
   * state's decisions, changing state when appropriate.
   */
  switch (approach_state) {

    // INIT state - Display switch status and ensure all are "OFF"
    case APPROACH_INIT:
      // All switches must be "off" before our approach sequence can be started
      // Since we save these as boolean (true/false) we can do this check on one
      // line that could be read as "if thrust is not true and systems is not true
      // and confirm is not true then..."
      if (!thrust_lever && !systems_lever && !confirm_lever) {
        // All switches are now off, ready for pre-flight
        approach_state = APPROACH_PREFLIGHT;  // Change state to Preflight
      }
      break;

    // PREFLIGHT state - All switches off.  Switch all on to begin approach
    case APPROACH_PREFLIGHT:
      // Once we have enabled thrusters and systems and confirmed we're ready
      // then switch to in-flight radar display.
      if (thrust_lever && systems_lever && confirm_lever) {  // All switches are "on"
        approach_state = APPROACH_IN_FLIGHT;                 // change to in-flight state
      }
      break;

    // FINAL state - Lower gear, we're about to land!
    case APPROACH_FINAL:
      // Check to see if a gear change button is pressed.  Do NOT wait for a key.
      // NOTE - code then drops into in-flight state!!
      // VVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVVV

    // IN-FLIGHT state - Add thrust to move closer to mother ship.
    // (Remember, you will have to REDUCE thrust as you get closer)
    case APPROACH_IN_FLIGHT:

      switch (controlButtonPressed()) {
        case RAISE_SPEED:
          lander_speed++;  // increase velocity
          // If this is first time increasing speed then save the start time
          if (approach_start_time == 0) {
            approach_start_time = millis();
          }
          break;
        case LOWER_SPEED:
          // lower speed unless stopped
          if (lander_speed > 0) {
            lander_speed--;
          }
          break;
        case LOWER_GEAR:                           // Lower landing gear unless already lowered
          if (approach_state == APPROACH_FINAL) {  // Only works on final approach
            // Lowering gear is an animation created by changing bitmaps each frame
            // until the gear is completely lowered.
            if (current_gear_bitmap_index != GEAR_BITMAP_COUNT - 1) {
              gear_state = GEAR_LOWERING;  // increases bitmap index until lowered
            }
          }
          break;
        case RAISE_GEAR:  // Raise landing gear unless already raised
          // Raising gear is an animation created by changing the bitmap index
          // each frame until gear is up.
          if (current_gear_bitmap_index != 0) {  // Ignore if gear is already up
            gear_state = GEAR_RAISING;
          }
        case STEER_UP:
          mother_ship_y_offset++;  // Steer lander one pixel UP
          break;
        case STEER_DOWN:
          mother_ship_y_offset--;  // Steer lander one pixel DOWN
          break;
        case STEER_LEFT:
          mother_ship_x_offset++;  // Steer lander one pixel LEFT
          break;
        case STEER_RIGHT:
          mother_ship_x_offset--;  // Steer lander one pixel RIGHT
          break;
        case STEER_UP_RIGHT:
          mother_ship_x_offset--;  // Steer lander one pixel UP and RIGHT
          mother_ship_y_offset++;
          break;
        case STEER_UP_LEFT:
          mother_ship_x_offset++;  // Steer lander one pixel UP and LEFT
          mother_ship_y_offset++;
          break;
        case STEER_DOWN_RIGHT:
          mother_ship_x_offset--;  // Steer lander one pixel DOWN and RIGHT
          mother_ship_y_offset--;
          break;
        case STEER_DOWN_LEFT:
          mother_ship_x_offset++;  // Steer lander one pixel DOWN and LEFT
          mother_ship_y_offset--;
          break;
      }

      // Here we compute the drift of the mother ship using random numbers.
      // The mother ship cannot drift off the display, done by setting a
      // maximum drift.
      const byte MAX_DRIFT = 18;

      mother_ship_x_offset += getRandomDrift();  // returns -1, 0 or 1
      mother_ship_y_offset += getRandomDrift();  // returns -1, 0 or 1
      // Ensure mother ship doesn't drift off our radar display
      if (mother_ship_x_offset > MAX_DRIFT) mother_ship_x_offset = MAX_DRIFT;
      if (mother_ship_x_offset < -MAX_DRIFT) mother_ship_x_offset = -MAX_DRIFT;
      if (mother_ship_y_offset > MAX_DRIFT) mother_ship_y_offset = MAX_DRIFT;
      if (mother_ship_y_offset < -MAX_DRIFT) mother_ship_y_offset = -MAX_DRIFT;

      // Prepare for landing on final approach
      if (lander_distance < (INITIAL_DISTANCE / 10)) {
        approach_state = APPROACH_FINAL;  // on final approach - enable gear and warn
      }
      break;
  }

  // Because we specified our gear states as 0, 1 or -1 we can change bitmaps by
  // simply adding the gear state to our current gear bitmap index.
  current_gear_bitmap_index += gear_state;

  // If the gear animation has completed (index is either 0 or the index of our last bitmap)
  // then we change the gear state to IDLE to complete animation.
  if (current_gear_bitmap_index == 0 || current_gear_bitmap_index == GEAR_BITMAP_COUNT - 1) {
    gear_state = GEAR_IDLE;
  }

  // Update our lander display (OLED) using firstPage()/nextPage() methods which
  // use a smaller buffer to save memory.  Draw the exact SAME display each time
  // through this loop!
  lander_display.firstPage();
  do {
    switch (approach_state) {
      // Display switch status for INIT and PREFLIGHT states.
      case APPROACH_INIT:
      case APPROACH_PREFLIGHT:
        displayPreFlight(approach_state, thrust_lever, systems_lever, confirm_lever);
        break;

      case APPROACH_FINAL:
        displayFinal(current_gear_bitmap_index);
      case APPROACH_IN_FLIGHT:
        displayInFlight(lander_distance, lander_speed,
                        mother_ship_x_offset, mother_ship_y_offset);
        break;
    }
  } while (lander_display.nextPage());

  lander_distance -= lander_speed;  // Adjust distance by current speed

  // END OF FLIGHT!
  //
  // When we reach the mother ship (distance <= 0) then determine success
  // or failure and display finaly screen alternating with last radar image.
  char* ending_bitmp;
  if (lander_distance <= 0) {
    // Check to see if our lander landed inside the mother ship target box.
    if (abs(mother_ship_x_offset) < ((MAX_MOTHER_SHIP_WIDTH + 1) / 2)
        && abs(mother_ship_y_offset) < ((MAX_MOTHER_SHIP_HEIGHT + 1) / 2)) {
      lander_distance = 0;
      // We hit the target.  Now check speed to see if we were slow enough
      if (lander_speed <= 2) {  // Max safe landing speed is 2

        // Speed OK, but did we remember to lower the landing gear?
        if (current_gear_bitmap_index == GEAR_BITMAP_COUNT - 1) {  // Gear is down!
          ending_bitmp = ENDING_BITMAP_SUCCESS;                    // SUCCESS!
        } else {
          // Oops, gear is up.  Damage to lander, but we survived.
          ending_bitmp = ENDING_BITMAP_NO_GEAR;
        }
      } else {
        // Speed is too fast!  Lander AND mother ship destroyed.  (Ouch!)
        ending_bitmp = ENDING_BITMAP_TOO_FAST;
      }
    } else {
      // Missed the mother ship.  No fuel for another try.  Bye!
      ending_bitmp = ENDING_BITMAP_MISSED_MOTHER_SHIP;
    }

    // Show final distance
    distance_display.showNumberDec(0);

    // Calculate elapsed time (in ms) from first thrust.
    unsigned long elapsed_time = millis() - approach_start_time;

    // Now format to fractional seconds (SS.SSS) using sprintf
    char buffer[20];  // buffer long enough for final display line.

    // Since elapse time is a long integer we can get the number of seconds
    // by simply dividing by 1000 and the fractional portion is dropped.  The
    // Modulo operator ('%') returns the REMAINDER after dividing left side by
    // the value on the right.  This gives us the fractional number seconds.
    // Sprintf() uses "lu" to indicate that the value is a "unsigned long"
    // ("lu" does NOT work!).
    sprintf(buffer, "%4lu.%03lu Sec", elapsed_time / 1000, elapsed_time % 1000);

    // Final display.  Alternate between splash screen with time and
    // final radar view.
    do {
      lander_display.firstPage();
      do {
        lander_display.drawStr(0, 0, buffer);
        lander_display.drawXBMP(0, 10, ENDING_BITMAP_WIDTH, ENDING_BITMAP_HEIGHT, ending_bitmp);
      } while (lander_display.nextPage());
      delay(2000);

      lander_display.firstPage();
      do {
        displayFinal(current_gear_bitmap_index);
        displayInFlight(lander_distance, lander_speed,
                        mother_ship_x_offset, mother_ship_y_offset);
      } while (lander_display.nextPage());
      delay(2000);
    } while (true);  // repeat this final display until HERO is reset
    // NEVER REACHED.  THIS IS OUR FINAL EXECUTION OF LOOP();
  }
  delay(100);  // Delay 1/10 second before next loop
}

// ************************************************
//             Preflight display
// ************************************************
// Update lander display with the status of our switches for INIT and PREFLIGHT states
void displayPreFlight(enum APPROACH_STATE approach_state,
                      bool thruster_lever,
                      bool systems_lever,
                      bool confirm_lever) {
  // Display all text referenced from upper left bit X, Y
  lander_display.setFontPosTop();

  // Draw title lines at top of display, updating y_offset afterwards
  byte y_offset = drawString(0, 0, "Exploration Lander");
  y_offset = drawString(0, y_offset, "Approach Sequence");

  // Set y_offset to point four lines above bottom of display
  y_offset = lander_display.getDisplayHeight() - (4 * lander_display.getMaxCharHeight());
  // Display status of each switch
  y_offset = drawString(0, y_offset,
                        (String("Thrusters: ") + String(thruster_lever ? "ON" : "OFF")).c_str());
  y_offset = drawString(0, y_offset,
                        (String("Systems  : ") + String(systems_lever ? "ON" : "OFF")).c_str());
  y_offset = drawString(0, y_offset,
                        (String("Confirm  : ") + String(confirm_lever ? "ON" : "OFF")).c_str());

  // Display final status line
  drawString(0, y_offset, (String("Countdown ") + liftoffStateToString(approach_state)).c_str());
}

// ************************************************
//   In-Flight display (including final approach)
// ************************************************
// Radar display for steering into mother ship docking bay.
void displayInFlight(int lander_distance,
                     int lander_speed,
                     int mother_ship_x_offset,
                     int mother_ship_y_offset) {

  // Mother ship initially appears as a single dot, but expands into a rectangle
  // as we get closer.  Scaled based on the maximum width, from 1 to MAX.
  //
  // Divide distance to mother ship into segments.  The number of segments is
  // one less than the width of our mother ship.
  const unsigned int SEGMENT_SIZE = INITIAL_DISTANCE / (MAX_MOTHER_SHIP_WIDTH - 1);
  byte segment_number = lander_distance / SEGMENT_SIZE;  // from (width - 1) to 0

  // subtract segment number from width/height to get visible width (minimum 1)
  int mother_ship_width = MAX_MOTHER_SHIP_WIDTH - segment_number;
  int mother_ship_height = MAX_MOTHER_SHIP_HEIGHT - segment_number;
  if (mother_ship_height < 1) {
    mother_ship_height = 1;  // Always at least 1 pixel high
  }

  // Display distance to mother ship on our distance display
  distance_display.showNumberDec(lander_distance);

  // coordinates of the center of our radar display
  const byte RADAR_CENTER_X = (lander_display.getDisplayWidth() / 2 / 2);  // center of left half
  const byte RADAR_CENTER_Y = (lander_display.getDisplayHeight() / 2);     // Vertical center
  const byte RADAR_RADIUS = 25;

  // Display bitmaps with 0 bits set to transparent.  This allows us to overlay
  // our arrows over the radar circle cleanly.
  lander_display.setBitmapMode(1);

  // Draw radar display circle and center pointer dot.
  lander_display.drawCircle(RADAR_CENTER_X, RADAR_CENTER_Y, RADAR_RADIUS);
  lander_display.drawPixel(RADAR_CENTER_X, RADAR_CENTER_Y);

  //====================================================================
  //====================================================================

  /*
   * As the mother ship's radar return drifts on the screen this section
   * of the code will display an arrow on the outside of the radar circle.
   *
   * The first constants can be changed so that the arrows don't appear
   * until the target pointer is outside the landing bay box, but currently
   * the arrows appear after small amounts of drift.
   *
   * The coordinates for the arrows were originally generated by ChatGPT
   * and then individually tweeked for perfect location.  Because of this
   * the coordinates will need to be manually adjusted if the radius of
   * the circle is changed.
   */
  const int DRIFT_BEFORE_ARROW_X = 2;  // try (mother_ship_width / 2) - 2; for late arrows
  const int DRIFT_BEFORE_ARROW_Y = 2;  // try (mother_ship_height / 2) - 2; for late arrows

  // Outer set of if/else statements check for left/right drift (X coordinate)
  if (mother_ship_x_offset < -DRIFT_BEFORE_ARROW_X) {  // left of center
    // Inner set of if/else statements check for up/down drift (Y coordinate)
    if (mother_ship_y_offset < -DRIFT_BEFORE_ARROW_Y) {                             // above center
      lander_display.drawXBMP(9, 9, ARROW_SIZE_X, ARROW_SIZE_Y, ARROW_UP_LEFT);     // Up-Left
    } else if (mother_ship_y_offset > DRIFT_BEFORE_ARROW_Y) {                       // below center
      lander_display.drawXBMP(8, 45, ARROW_SIZE_X, ARROW_SIZE_Y, ARROW_DOWN_LEFT);  // Down-Left
    } else {                                                                        // close to center in Y direction
      lander_display.drawXBMP(1, 27, ARROW_SIZE_X, ARROW_SIZE_Y, ARROW_LEFT);       // Left
    }
  } else if (mother_ship_x_offset > DRIFT_BEFORE_ARROW_X) {                           // Right of center
    if (mother_ship_y_offset < -DRIFT_BEFORE_ARROW_Y) {                               // above center
      lander_display.drawXBMP(45, 8, ARROW_SIZE_X, ARROW_SIZE_Y, ARROW_UP_RIGHT);     // Up-Right
    } else if (mother_ship_y_offset > DRIFT_BEFORE_ARROW_Y) {                         // below center
      lander_display.drawXBMP(45, 45, ARROW_SIZE_X, ARROW_SIZE_Y, ARROW_DOWN_RIGHT);  // Down-Right
    } else {                                                                          // close to center in Y direction
      lander_display.drawXBMP(53, 27, ARROW_SIZE_X, ARROW_SIZE_Y, ARROW_RIGHT);       // Right
    }
  } else {                                                                      // close to center in X direction
    if (mother_ship_y_offset < -DRIFT_BEFORE_ARROW_Y) {                         // above center
      lander_display.drawXBMP(27, 1, ARROW_SIZE_X, ARROW_SIZE_Y, ARROW_UP);     // Up
    } else if (mother_ship_y_offset > DRIFT_BEFORE_ARROW_Y) {                   // below center
      lander_display.drawXBMP(27, 53, ARROW_SIZE_X, ARROW_SIZE_Y, ARROW_DOWN);  // Down
    }                                                                           // else NO arrow as we're close to target
  }

  // We will use sprintf() to format the lander speed line
  char buffer[9];                                                               // Length of line plus one for terminating null.
  sprintf(buffer, "SPD: %2d", lander_speed);                                    // format speed into buffer
  int width = lander_display.getStrWidth(buffer);                               // width of string in pixels
  lander_display.drawStr(lander_display.getDisplayWidth() - width, 0, buffer);  // display in upper right

  // Now draw the image of the mother ship as a rectangle, sized based on distance and
  // offset the x/y coordinates so that ship offset is always from the CENTER of the
  // mother ship.
  byte x_offset = RADAR_CENTER_X + mother_ship_x_offset - (mother_ship_width / 2);
  byte y_offset = RADAR_CENTER_Y + mother_ship_y_offset - (mother_ship_height / 2);
  lander_display.drawFrame(x_offset, y_offset, mother_ship_width, mother_ship_height);
}

// ************************************************
// When lander is about to land we'll add an image of the lander
// with landing gear status along with gear prompt messages.
void displayFinal(int current_gear_bitmap_index) {
  int gear_down_index = GEAR_BITMAP_COUNT - 1;  // index of the LAST bitmap image

  // Coordinates below  manually adjusted to display in upper right
  // two lines below the speed line.
  byte x_offset = (lander_display.getDisplayWidth() / 2) + 11;
  byte y_offset = lander_display.getMaxCharHeight() * 2;  // offset to third line
  if (current_gear_bitmap_index == 0) {                   // Gear is up.  Prompt to lower
    lander_display.drawStr(x_offset, y_offset, "Drop gear");
  } else if (current_gear_bitmap_index < gear_down_index) {  // Gear is lowering
    lander_display.drawStr(x_offset, y_offset, "Lowering");
  } else {
    lander_display.drawStr(x_offset, y_offset, "Gear OK");  // Gear is down ()
  }

  // Calculate our x and y offsets to center our bitmap graphics
  // Get offsets to lower-right area of screen.  Height allows 3 lines of text above
  x_offset = (lander_display.getDisplayWidth() / 2);  // 64
  x_offset += ((lander_display.getDisplayWidth() - x_offset) - LANDING_GEAR_BITMAP_WIDTH) / 2;
  y_offset = lander_display.getDisplayHeight() - (lander_display.getMaxCharHeight() * 3);
  y_offset += ((lander_display.getDisplayHeight() - y_offset) - LANDING_GEAR_BITMAP_HEIGHT) / 2;

  // Draw current bitmap centered in lower right quadrant
  lander_display.drawXBMP(x_offset, y_offset,
                          LANDING_GEAR_BITMAP_WIDTH, LANDING_GEAR_BITMAP_HEIGHT,
                          LANDER_BITMAPS[current_gear_bitmap_index]);
}

// ************************************************
// "helper" function that returns a different string for each enum state.
String liftoffStateToString(enum APPROACH_STATE approach_state) {
  switch (approach_state) {
    case APPROACH_INIT:
      return ("Init");
      break;
    case APPROACH_PREFLIGHT:
      return ("Preflight");
      break;
  }
}

// ************************************************
// Draw a line of text on our OLED display at x, y, returning new y
// value that is immediately below the new line of text.
byte drawString(byte x, byte y, char* string) {
  lander_display.drawStr(x, y, string);
  return (y + lander_display.getMaxCharHeight());  // return new y_offset on display
}

// They Keypad library only returns a button value when it is initially
// pressed.  We wish to continue to get the same value for as long as
// a button is pressed.  This function keeps track of the last button
// pressed and returns it until the button is released or another
// button is pressed.
enum LANDER_CONTROLS controlButtonPressed() {
  static char last_key = NO_KEY;

  char current_key = lander_controls.getKey();
  if (current_key != NO_KEY) {
    last_key = current_key;  // New key seen, save as last
  }

  // If the button is released reset to NO_KEY
  if (lander_controls.getState() == RELEASED) {
    last_key = NO_KEY;
    current_key = NO_KEY;
  } else {
    current_key = last_key;  // button still pressed so return last button seen.
  }
  return (current_key);
}

const byte DRIFT_CONTROL = 3;  // Must be > 1.  Higher numbers slow drift rate

int getRandomDrift() {
  // Random(low, high) returns a random number from low to ONE LESS THAN high.
  // We use -1, 0 or 1 for the drift.  To *slow* the drift we can increae the
  // number of values that indicate "no drift" by generating numbers higher
  // than 1 and if the random number is higher we set drift to 0.
  // With a drift control of 3 we get random numbers (-1, 0, 1, 2) and if 2 we
  // change to 0, doubleing the times we get NO drift.
  int drift = random(-1, DRIFT_CONTROL);
  if (drift > 1) {  // Values over 1 are changed to 0
    drift = 0;
  }
  return (drift);
}
